-link\">\r\n				<i class=\"icon-note\"></i> \r\n				<span class=\"hidden-xs blink\">booking</span>\r\n				</a>\r\n				</li> -->\r\n				\r\n			  </ul>\r\n			  <div class=\"tab-content p-3\">\r\n				<!-- Profile Tab -->\r\n				<div class=\"tab-pane active show\" id=\"profile5\">\r\n				<div class=\"col-md-12\">\r\n				<div class=\"row\">\r\n				<div class=\"col-md-6\">\r\n				\r\n				<div id=\"luxCarousel\" class=\"carousel slide\" data-ride=\"carousel\">\r\n				  <div class=\"carousel-inner\">\r\n				  <div class=\"carousel-item active\">\r\n					<h3 style=\"text-align: center;\">Mercedes Benz</h3>\r\n					<img src=\"assets/images/booking/luxury/benzs.png\" class=\"d-block w-100\" alt=\"Suzuki Alto Image 1\">\r\n				  </div>\r\n				  <div class=\"carousel-item\">\r\n					<h3 style=\"text-align: center;\">BMW 520D</h3>\r\n					<img src=\"assets/images/booking/luxury/bmw520d.png\" class=\"d-block w-100\" alt=\"Suzuki Alto Image 2\">\r\n				  </div>\r\n				  <div class=\"carousel-item\">\r\n					<h3 style=\"text-align: center;\">Jaguar RXF</h3>\r\n					<img src=\"assets/images/booking/luxury/jaguarxf.png\" class=\"d-block w-100\" alt=\"Suzuki Alto Image 2\">\r\n				  </div>\r\n				  \r\n				  \r\n				  </div>\r\n				  <a class=\"carousel-control-prev\" href=\"#luxCarousel\" role=\"button\" data-slide=\"prev\">\r\n				  <span class=\"carousel-control-prev-icon\" aria-hidden=\"true\"></span>\r\n				  <span class=\"sr-only\">Previous</span>\r\n				  </a>\r\n				  <a class=\"carousel-control-next\" href=\"#luxCarousel\" role=\"button\" data-slide=\"next\">\r\n				  <span class=\"carousel-control-next-icon\" aria-hidden=\"true\"></span>\r\n				  <span class=\"sr-only\">Next</span>\r\n				  </a>\r\n				</div>\r\n				</div>\r\n				\r\n			   \r\n				\r\n				\r\n			  \r\n				<div class=\"col-md-6\">\r\n				  <p style=\"text-align: justify; font-size: 14px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif\r\n				  ;\">The Mercedes-Benz lineup represents the