(9, 'document', 'rentacar', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '  \r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/breadcrumb/sr_bc_rentacar.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n        <div class=\"overlay\"></div>\r\n        <div class=\"container\">\r\n          <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n            <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n              <h1 class=\"mb-2 bread\">Rent A  Car</h1>\r\n              <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Rent A  Car <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </section>\r\n    \r\n  \r\n  \r\n      <section class=\"about-section\">\r\n      <div class=\"container\">\r\n          <div class=\"row clearfix\">\r\n              \r\n             <!--Content Column-->\r\n  <div class=\"content-column col-md-6 col-sm-12 col-xs-12\">\r\n    <div class=\"inner-column\">\r\n        <div class=\"sec-title\">\r\n            <h2 style=\"font-size: 30px; color: #a40000;  font-weight: bold;\">Rent A Car In Sri Lanka Has <br> Never Been Easier</h2>\r\n        </div>\r\n\r\n        <div class=\"text\" style=\"text-align: justify;\">\r\n            Want to explore the beautiful island of Sri Lanka freely? Our team is ready to help you find the perfect car rental solution.\r\n          \r\n        </div>\r\n        <div class=\"text\" style=\"text-align: justify;\">\r\n            Based in Seeduwa (10 minutes away from Colombo International Airport), SR Rent A Car is an independent car rental company in Sri Lanka since 2004. We offer luxurious customer service and affordable rates. Our personalized and professional approach ensures your satisfaction.\r\n            You can conveniently collect and return your vehicle at Bandaranaike International Airport or our Seeduwa office. Choose from a wide range of vehicles to suit your needs. Our helpful staff is available 24/7 to assist you with any queries.\r\n        </div>\r\n\r\n\r\n \r\n        \r\n\r\n  \r\n        <a href=\"[[~4]]\" class=\"theme-btn btn-style-three\">Rent A Car</a>\r\n        <!-- <a href=\"[[~4]]\" class=\"theme-btn btn-style-three\" style=\"margin-left: 35px;\">(+94) 777 780 729</a> -->\r\n    </div>\r\n  </div>\r\n  \r\n                \r\n                <!--Image Column-->\r\n                <div class=\"image-column col-md-6 col-sm-12 col-xs-12\">\r\n                  <div class=\"inner-column \" data-wow-delay=\"0ms\" data-wow-duration=\"1500ms\">\r\n                      <div class=\"image\">\r\n                            <img src=\"assets/images/rentacar/renthome.png\" alt=\"\">\r\n                            <div class=\"overlay-box\">\r\n                              <div class=\"year-box\"><span class=\"number\">20</span>Years <br> industry  <br> Expertise</div>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                \r\n            </div>\r\n        </div>\r\n    </section>\r\n  \r\n  \r\n  \r\n       <!-- Topic Cards -->\r\n         <div id=\"cards_landscape_wrap-2\">\r\n         \r\n          <div class=\"container\">\r\n            <h1 class=\"text-gradient\" style=\"font-size: 40px;text-align: left;\">Short Term Car Rentals</h1>\r\n              <div class=\"row\">\r\n                \r\n                  <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n                      <a href=\"\">\r\n                          <div class=\"card-flyer\">\r\n                              <div class=\"text-box\">\r\n                                  <div class=\"image-box\">\r\n                                      <img src=\"assets/images/rentacar/short_term.jpg\" alt=\"\" />\r\n                                  </div>\r\n                                  <div class=\"text-container\">\r\n                                      <h6 style=\"padding-top: 20px;\">Short Term Car Rentals</h6>\r\n                                      <p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car offer our customers access to a wide variety of the newest vehicles available for short-term hire by the day, week, month.</p>\r\n                                  </div>\r\n                              </div>\r\n                          </div>\r\n                      </a>\r\n                  </div>\r\n                  <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n                      <a href=\"\">\r\n                          <div class=\"card-flyer\">\r\n                              <div class=\"text-box\">\r\n                                  <div class=\"image-box\">\r\n                                      <img src=\"assets/images/rentacar/long_term.jpg\" alt=\"\" />\r\n                                  </div>\r\n                                  <div class=\"text-container\">                                    \r\n                                    <h6 style=\"padding-top: 20px;\">Long Term Car Rentals</h6>\r\n                                    <p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car offer you to hire a vehicle long term basis in Sri Lanka. We offer ultimate flexibility, reliability and affordability for your need.</p>\r\n                                  </div>\r\n                              </div>\r\n                          </div>\r\n                      </a>\r\n                  </div>\r\n                  <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n                      <a href=\"\">\r\n                          <div class=\"card-flyer\">\r\n                              <div class=\"text-box\">\r\n                                  <div class=\"image-box\">\r\n                                      <img src=\"assets/images/rentacar/corporate_rental.jpg\" alt=\"\" />\r\n                                  </div>\r\n  \r\n                                  <div class=\"text-container\">\r\n                                    <h6 style=\"padding-top: 20px;\">Corporate Car Rentals</h6>\r\n                                    <p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car has always been ahead of the game to provide excellent Corporate Car Rental services at competitive rates for businesses.</p>\r\n                                  </div>\r\n                              </div>\r\n                          </div>\r\n                      </a>\r\n                  </div>\r\n                  <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n                    <a href=\"\">\r\n                        <div class=\"card-flyer\">\r\n                            <div class=\"text-box\">\r\n                                <div class=\"image-box\">\r\n                                    <img src=\"assets/images/rentacar/selfdriving.jpg\" alt=\"\" />\r\n                                </div>\r\n  \r\n                                <div class=\"text-container\">\r\n                                    <h6 style=\"padding-top: 20px;\">Self Driven Car Rentals</h6>\r\n                                    <p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car provides a large range of self-drive cars, vans, and SUVs available in selecting shapes, sizes, and specifications. These come in different specifications and sizes and are available by the day, week, month or longer.</p>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n                <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n                  <a href=\"\">\r\n                      <div class=\"card-flyer\">\r\n                          <div class=\"text-box\">\r\n                              <div class=\"image-box\">\r\n                                  <img src=\"assets/images/rentacar/chauffeur.jpg\" alt=\"\" />\r\n                              </div>\r\n  \r\n                              <div class=\"text-container\">\r\n                                <h6 style=\"padding-top: 20px;\">Chauffeur Driven Car Rentals</h6>\r\n                                <p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car is best known for its top-notch personal chauffeur services in Sri Lanka. We make sure that you have the perfect chauffeur driven car for your occasion.</p>\r\n                              </div>\r\n                          </div>\r\n                      </div>\r\n                  </a>\r\n              </div>\r\n              <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n                <a href=\"\">\r\n                    <div class=\"card-flyer\">\r\n                        <div class=\"text-box\">\r\n                            <div class=\"image-box\">\r\n                                <img src=\"assets/images/rentacar/vip.jpg\" alt=\"\" />\r\n                            </div>\r\n  \r\n                            <div class=\"text-container\">\r\n                                <h6 style=\"padding-top: 20px;\">Luxury Car Rentals</h6>\r\n                                <p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">Here At SR Rent A Car we pride ourselves in offering a wide range of prestigious vehicles, from luxury saloons to sporty 4x4s.</p>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </a>\r\n            </div>\r\n              </div>\r\n          </div>\r\n      </div>\r\n  \r\n  \r\n      \r\n  <!-- Topic Cards -->\r\n  <div id=\"cards_landscape_wrap-2\" style=\"padding-bottom: 100px;\">\r\n    <div class=\"container\">\r\n        <h1 class=\"text-gradient\" style=\"font-size: 40px;text-align: left;\">Why Choose SR Rent A Car?</h1>\r\n        \r\n        <!-- Full-width paragraph -->\r\n        <div class=\"col-12\">\r\n            <p style=\"text-align: justify; font-size: 18px; margin-bottom: 30px;\">\r\n                SR Rent A Car offers reliable, flexible and cheap car rental services in Sri Lanka. As a rent a car company, we take pride in our trustworthy services to all our esteemed clients. Our wide range of rental cars is available all through the year. Our rental car services stretch from short term rentals to long term rentals at very affordable prices. Whether you are looking for a saloon car, station wagon, minivans, coaster bus and SUVs, we got you covered with low prices and ultimate customer care service. Below are some of the reasons why you should choose us.\r\n            </p>\r\n        </div>\r\n        \r\n        \r\n  \r\n  \r\n        <div class=\"container\">\r\n            <div class=\"row\">\r\n                <div class=\"col-md-6 col-md-offset-4\">\r\n                    <div class=\"panel panel-default coupon\">\r\n                      <div class=\"panel-heading\" id=\"head\">\r\n                       \r\n                           \r\n                            <span class=\"hidden-xs\" style=\"text-align: center;\">Professional Services</span>\r\n                         \r\n                 \r\n                      </div>\r\n                      <div class=\"panel-body\">\r\n         \r\n               \r\n                        <div class=\"col-md-12\">\r\n                            <p class=\"disclosure\" style=\"text-align: justify;\">The happiness & satisfaction of our customer is the most valued components of our business. You will be provided with a vehicle that you will have to keep you relaxed, safe, calm and extremely comfortable. We guarantee you exceptional, first-class services that give 100% customer satisfaction.</p>\r\n                        </div>\r\n                      </div>\r\n                     \r\n                    </div>\r\n                </div>\r\n                <div class=\"col-md-6 col-md-offset-4\">\r\n                    <div class=\"panel panel-default coupon\">\r\n                      <div class=\"panel-heading\" id=\"head\">\r\n                       \r\n                           \r\n                            <span class=\"hidden-xs\" style=\"text-align: center;\">Knowledgeable Staff</span>\r\n                         \r\n                 \r\n                      </div>\r\n                      <div class=\"panel-body\">\r\n         \r\n               \r\n                        <div class=\"col-md-12\">\r\n                            <p class=\"disclosure\" style=\"text-align: justify;\">Because our staff are local residents and have years of experience offering vehicle rentals from Sri Lanka, you can be confident you’ll get answers to all of your questions. You’ll also receive satisfactory solutions to any problems along the way.</p>\r\n                        </div>\r\n                      </div>\r\n                     \r\n                    </div>\r\n                </div>\r\n           \r\n            </div>\r\n            \r\n         \r\n  \r\n            <div class=\"row\">\r\n\r\n                <div class=\"col-md-6 col-md-offset-4\">\r\n                    <div class=\"panel panel-default coupon\">\r\n                      <div class=\"panel-heading\" id=\"head\">\r\n                       \r\n                           \r\n                            <span class=\"hidden-xs\" style=\"text-align: center;\">Flexible Pick Up and Drop Off Service </span>\r\n                         \r\n                 \r\n                      </div>\r\n                      <div class=\"panel-body\">\r\n         \r\n               \r\n                        <div class=\"col-md-12\">\r\n                            <p class=\"disclosure\" style=\"text-align: justify;\">Our friendly staff pick you up from the terminal of your choice. From there you can enjoy your trip with the seamless comforts of your own transportation. Once you are ready to hand back the keys, simply meet our team at a prearranged time and we’ll happily drop you off at the airport with plenty of time to spare.</p>\r\n                        </div>\r\n                      </div>\r\n                     \r\n                    </div>\r\n                </div>\r\n                <div class=\"col-md-6 col-md-offset-4\">\r\n                    <div class=\"panel panel-default coupon\">\r\n                      <div class=\"panel-heading\" id=\"head\">\r\n                       \r\n                           \r\n                            <span class=\"hidden-xs\" style=\"text-align: center;\">Diverse Fleet</span>\r\n                         \r\n                 \r\n                      </div>\r\n                      <div class=\"panel-body\">\r\n         \r\n               \r\n                        <div class=\"col-md-12\">\r\n                            <p class=\"disclosure\" style=\"text-align: justify;\">We can provide you with a wide range of different vehicles. Our diverse vehicle fleet includes Economy, Compact, Family Sedan, Pickup 2x4, SUVs, Station Wagons, Seven-Seaters and many more.</p>\r\n                        </div>\r\n                      </div>\r\n                     \r\n                    </div>\r\n                </div>\r\n      \r\n   \r\n            </div>\r\n\r\n            <div class=\"row\">\r\n\r\n                \r\n                <div class=\"col-md-6 col-md-offset-4\">\r\n                    <div class=\"panel panel-default coupon\">\r\n                      <div class=\"panel-heading\" id=\"head\">\r\n                       \r\n                           \r\n                            <span class=\"hidden-xs\" style=\"text-align: center;\">Affordable Rates Guaranteed</span>\r\n                         \r\n                 \r\n                      </div>\r\n                      <div class=\"panel-body\">\r\n         \r\n               \r\n                        <div class=\"col-md-12\">\r\n                            <p class=\"disclosure\" style=\"text-align: justify;\">Whether you\'re gearing up to take your family on a road trip or are heading out on a business excursion, you\'ll find our rates are personalized to you. Providing affordable car rental rates throughout the year will be one of the key aspects of SR Rent A Car.</p>\r\n                        </div>\r\n                      </div>\r\n                     \r\n                    </div>\r\n                </div>\r\n   \r\n            </div>\r\n            \r\n          \r\n           \r\n        \r\n        </div>\r\n  \r\n       \r\n  \r\n  \r\n  </body>\r\n  </html>\r\n  \r\n  </div>\r\n    </div>\r\n  \r\n  ', 1, 2, 7, 1, 1, 1, 1725434763, 1, 1740032965, 0, 0, 0, 1725434760, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1);
INSERT INTO `modx_site_content` (`id`, `type`, `pagetitle`, `longtitle`, `description`, `alias`, `link_attributes`, `published`, `pub_date`, `unpub_date`, `parent`, `isfolder`, `introtext`, `content`, `richtext`, `template`, `menuindex`, `searchable`, `cacheable`, `createdby`, `createdon`, `editedby`, `editedon`, `deleted`, `deletedon`, `deletedby`, `publishedon`, `publishedby`, `menutitle`, `donthit`, `privateweb`, `privatemgr`, `content_dispo`, `hidemenu`, `class_key`, `context_key`, `content_type`, `uri`, `uri_override`, `hide_children_in_tree`, `show_in_tree`, `properties`, `alias_visible`) VALUES
(10, 'document', 'faq', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '  \r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n        <div class=\"overlay\"></div>\r\n        <div class=\"container\">\r\n          <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n            <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n              <h1 class=\"mb-2 bread\">FAQ</h1>\r\n              <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span> FREQUENTLY ASKED QUESTIONS<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </section>\r\n    \r\n\r\n\r\n      <section class=\"about-section\">\r\n    	<div class=\"container\">\r\n            <div class=\"row\">\r\n                <div class=\"col-lg-4\">\r\n                    <div class=\"nav nav-pills faq-nav\" id=\"faq-tabs\" role=\"tablist\" aria-orientation=\"vertical\">\r\n                        <a href=\"#tab1\" class=\"nav-link active\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab1\" aria-selected=\"true\">\r\n                            <i class=\"mdi mdi-help-circle\"></i> Rental Requirements  \r\n                        </a>\r\n                        <a href=\"#tab2\" class=\"nav-link\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab2\" aria-selected=\"false\">\r\n                            <i class=\"mdi mdi-account\"></i>Reservations                          \r\n                        </a>\r\n                        <a href=\"#tab3\" class=\"nav-link\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab3\" aria-selected=\"false\">\r\n                            <i class=\"mdi mdi-account-settings\"></i>During Rental Period                       \r\n                        </a>\r\n                        <a href=\"#tab4\" class=\"nav-link\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab4\" aria-selected=\"false\">\r\n                            <i class=\"mdi mdi-heart\"></i> Miscellaneous\r\n                        </a>\r\n                        <a href=\"#tab5\" class=\"nav-link\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab5\" aria-selected=\"false\">\r\n                            <i class=\"mdi mdi-coin\"></i> Transactions\r\n                        </a>\r\n                        <a href=\"#tab6\" class=\"nav-link\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab6\" aria-selected=\"false\">\r\n                            <i class=\"mdi mdi-help\"></i> General help\r\n                        </a>\r\n                    </div>\r\n                </div>\r\n                <div class=\"col-lg-8\">\r\n                    <div class=\"tab-content\" id=\"faq-tab-content\">\r\n                        <div class=\"tab-pane show active\" id=\"tab1\" role=\"tabpanel\" aria-labelledby=\"tab1\">\r\n                            <div class=\"accordion\" id=\"accordion-tab-1\">\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-1-heading-1\">\r\n                                      <h5>\r\n                                        <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-1-content-1\" aria-expanded=\"false\" aria-controls=\"accordion-tab-1-content-1\">\r\n                                            What do I need to rent a car?\r\n                                        </button>\r\n                                      </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-1-content-1\" aria-labelledby=\"accordion-tab-1-heading-1\" data-parent=\"#accordion-tab-1\">\r\n                                      <div class=\"faq-body\">\r\n                                        <p>\r\n                                            You must have the following documents with you in order to rent a car. \r\n                                        \r\n                                            A valid passport.\r\n                                            A valid international driving licence.\r\n                                            A valid temporary local (Sri Lankan) driving licence.\r\n                                            Valid working credit card.\r\n                                        </p>\r\n                                      </div>\r\n                                    </div>\r\n                                  </div>\r\n                                  \r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-1-heading-2\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-1-content-2\" aria-expanded=\"false\" aria-controls=\"accordion-tab-1-content-2\">What type of driver\'s license do I need to drive in Sri Lanka?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-1-content-2\" aria-labelledby=\"accordion-tab-1-heading-2\" data-parent=\"#accordion-tab-1\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>\r\n                                                You’ll need a valid International Driving Permit issued by a competent government institution that conforms to the format specified by the Geneva Convention on Road Traffic 1949.\r\n                                                You’ll also need to obtain a Temporary Sri Lanka Driving Permit (TDL).\r\n                                                    Now it is COMPULSORY to obtain a TDL for every foreigner to drive a vehicle in Sri Lanka.\r\n                                            </p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-1-heading-3\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-1-content-3\" aria-expanded=\"false\" aria-controls=\"accordion-tab-1-content-3\">How can I obtain a temporary driving license (TDL) in Sri Lanka?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-1-content-3\" aria-labelledby=\"accordion-tab-1-heading-3\" data-parent=\"#accordion-tab-1\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>\r\n                                                You’ll have two options.\r\n                                            \r\n                                                You can obtain it yourself when you are in Sri Lanka. (It can not be done online & your only option will be by visiting the Sri Lanka Motor Trafic Department)\r\n                                                We can obtain it on behalf of you. You just need to mention that you need a TDL when you request a quote.\r\n                                            </p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-1-heading-4\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-1-content-4\" aria-expanded=\"false\" aria-controls=\"accordion-tab-1-content-4\">Can elderly people also rent cars?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-1-content-4\" aria-labelledby=\"accordion-tab-1-heading-4\" data-parent=\"#accordion-tab-1\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>Yes. No age restrictions are in place. Anybody with a valid driver’s license can rent a vehicle.</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"tab-pane\" id=\"tab2\" role=\"tabpanel\" aria-labelledby=\"tab2\">\r\n                            <div class=\"accordion\" id=\"accordion-tab-2\">\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-2-heading-1\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-2-content-1\" aria-expanded=\"false\" aria-controls=\"accordion-tab-2-content-1\">What is included in the rental price, and are there any additional fees?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse \" id=\"accordion-tab-2-content-1\" aria-labelledby=\"accordion-tab-2-heading-1\" data-parent=\"#accordion-tab-2\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p style=\"text-align: justify;\">\r\n                                                The basic rental price typically covers the vehicle and standard insurance. \r\n                                                However, there are several additional optional services and fees that customers may choose based on their needs. These may include:\r\n                                            </p>\r\n                                            <ul style=\"padding-left: 20px;\">\r\n                                                <li>Unlimited mileage or mileage restrictions</li>\r\n                                                <li>Additional driver fees</li>\r\n                                                <li>Baby seat rental</li>\r\n                                                <li>Additional navigation systems</li>\r\n                                                <li>Fuel charges (full-to-full or prepaid fuel options)</li>\r\n                                                <li>Optional insurance upgrades</li>\r\n                                            </ul>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-2-heading-2\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-2-content-2\" aria-expanded=\"false\" aria-controls=\"accordion-tab-2-content-2\">Can I drop off the car at a different location from where I picked it up?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-2-content-2\" aria-labelledby=\"accordion-tab-2-heading-2\" data-parent=\"#accordion-tab-2\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p style=\"text-align: justify;\">One-way rentals are possible but typically incur an additional fee. Our rental staff will conduct a thorough vehicle inspection at the collection point to ensure the condition of the vehicle before finalizing the rental agreement.</p>\r\n                                        \r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-2-heading-3\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-2-content-3\" aria-expanded=\"false\" aria-controls=\"accordion-tab-2-content-3\">What happens if I need to cancel my reservation?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-2-content-3\" aria-labelledby=\"accordion-tab-2-heading-3\" data-parent=\"#accordion-tab-2\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p style=\"text-align: justify;\">Cancellation policies vary depending on the type of reservation and how close it is to the pickup date. </p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-2-heading-4\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-2-content-4\" aria-expanded=\"false\" aria-controls=\"accordion-tab-2-content-4\">Can I modify my existing reservation?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-2-content-4\" aria-labelledby=\"accordion-tab-2-heading-4\" data-parent=\"#accordion-tab-2\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p style=\"text-align: justify;\">Reservation modifications are possible, preferably with at least 24 hours\' notice. Changes can even be made at the collection point, subject to vehicle availability. </p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-2-heading-5\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-2-content-4\" aria-expanded=\"false\" aria-controls=\"accordion-tab-2-content-4\">How much will it cost to modify a reservation?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-2-content-4\" aria-labelledby=\"accordion-tab-2-heading-4\" data-parent=\"#accordion-tab-2\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p style=\"text-align: justify;\">Modification costs vary depending on the vehicle model you select. We offer flexible charge policies for reservation changes, ensuring you have the most convenient rental experience possible. </p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n\r\n\r\n\r\n\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"tab-pane\" id=\"tab3\" role=\"tabpanel\" aria-labelledby=\"tab3\">\r\n                            <div class=\"accordion\" id=\"accordion-tab-3\">\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-3-heading-1\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-3-content-1\" aria-expanded=\"false\" aria-controls=\"accordion-tab-3-content-1\">What should I do if I damage the car?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse \" id=\"accordion-tab-3-content-1\" aria-labelledby=\"accordion-tab-3-heading-1\" data-parent=\"#accordion-tab-3\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>In the event that the customer causes an accident or defacement to the vehicle during the rental period, the user shall be required to pay the non-operation charge (NOC) as partial compensation for the loss of earnings incurred for repairs or cleaning, regardless of the degree of damage or the length of time required for repairs/cleaning.</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-3-heading-2\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-3-content-2\" aria-expanded=\"false\" aria-controls=\"accordion-tab-3-content-2\">What should I do in case of an accident or theft while renting a car?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-3-content-2\" aria-labelledby=\"accordion-tab-3-heading-2\" data-parent=\"#accordion-tab-3\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>\r\n                                                Please follow the procedure below if you get involved in an accident:\r\n                                            \r\n                                                Move the vehicle to a safe location to prevent further accidents.\r\n                                                Assist all injured parties.\r\n                                                Report the accident to the police.\r\n                                                Get the details of the other party.\r\n                                                Contact the Global Customer Desk*.\r\n                                            \r\n                                                Do not negotiate a private settlement on the spot. Private settlements will invalidate the insurance, which will require the user to pay the entire cost.\r\n                                                In the occurrence of a theft, please report it to the police and the office.</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-3-heading-3\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-3-content-3\" aria-expanded=\"false\" aria-controls=\"accordion-tab-3-content-3\">Are there any restrictions on mileage when using a rental car?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-3-content-3\" aria-labelledby=\"accordion-tab-3-heading-3\" data-parent=\"#accordion-tab-3\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>Yes, You can travel only 100km per day or 3000km per month (if you are renting for a month). Extra mileage will be charged based on vehicle category.</p>\r\n                                            \r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-3-heading-4\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-3-content-4\" aria-expanded=\"false\" aria-controls=\"accordion-tab-3-content-4\">Can my pet ride in the car?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-3-content-4\" aria-labelledby=\"accordion-tab-3-heading-4\" data-parent=\"#accordion-tab-3\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>No. Pets aren’t allowed to be taken on your rental vehicle. </p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"tab-pane\" id=\"tab4\" role=\"tabpanel\" aria-labelledby=\"tab4\">\r\n                            <div class=\"accordion\" id=\"accordion-tab-4\">\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-4-heading-1\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-4-content-1\" aria-expanded=\"false\" aria-controls=\"accordion-tab-4-content-1\">What do I need to bring when picking up the car?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse \" id=\"accordion-tab-4-content-1\" aria-labelledby=\"accordion-tab-4-heading-1\" data-parent=\"#accordion-tab-4\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>\r\n                                                Your passport.\r\n                                                Your International Diving Licence.\r\n                                                Your Sri Lanka Temporary Driving Licence. (If you don’t have one we can arrange one for you)\r\n                                                Your Credit Card \r\n                                            </p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                        \r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-4-heading-3\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-4-content-3\" aria-expanded=\"false\" aria-controls=\"accordion-tab-4-content-3\">Can I make changes to the reservation when I pick up the car?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-4-content-3\" aria-labelledby=\"accordion-tab-4-heading-3\" data-parent=\"#accordion-tab-4\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>Yes, you can make changes to your reservation at the pickup. Things such as the rental period can be easily be changed. But your selected vehicle category & extras are subject to availability. </p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-4-heading-4\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-4-content-4\" aria-expanded=\"false\" aria-controls=\"accordion-tab-4-content-4\">Can I arrange for the car to be delivered to the airport?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-4-content-4\" aria-labelledby=\"accordion-tab-4-heading-4\" data-parent=\"#accordion-tab-4\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>Yes, you can pick up your requested vehicle from the airport.</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                        <!-- <div class=\"tab-pane\" id=\"tab5\" role=\"tabpanel\" aria-labelledby=\"tab5\">\r\n                            <div class=\"accordion\" id=\"accordion-tab-5\">\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-5-heading-1\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-5-content-1\" aria-expanded=\"false\" aria-controls=\"accordion-tab-5-content-1\">Say what?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse \" id=\"accordion-tab-5-content-1\" aria-labelledby=\"accordion-tab-5-heading-1\" data-parent=\"#accordion-tab-5\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>That could be \'my\' beautiful soul sitting naked on a couch. If I could just learn to play this stupid thing. Oh, I don\'t have time for this. I have to go and buy a single piece of fruit with a coupon and then return it, making people wait behind me while I complain. I\'m just glad my fat, ugly mama isn\'t alive to see this day. For one beautiful night I knew what it was like to be a grandmother. Subjugated, yet honored. But existing is basically all I do! I never loved you.</p>\r\n                                            <p><strong>Example: </strong>A sexy mistake. And I\'d do it again!</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-5-heading-2\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-5-content-2\" aria-expanded=\"false\" aria-controls=\"accordion-tab-5-content-2\">Who\'s brave enough to fly into something we all keep calling a death sphere?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-5-content-2\" aria-labelledby=\"accordion-tab-5-heading-2\" data-parent=\"#accordion-tab-5\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>Maybe I love you so much I love you no matter who you are pretending to be. Ah, the \'Breakfast Club\' soundtrack! I can\'t wait til I\'m old enough to feel ways about stuff! Now Fry, it\'s been a few years since medical school, so remind me.</p>\r\n                                            <p><strong>Example: </strong>Disemboweling in your species: fatal or non-fatal?</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-5-heading-3\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-5-content-3\" aria-expanded=\"false\" aria-controls=\"accordion-tab-5-content-3\">You mean while I\'m sleeping in it?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-5-content-3\" aria-labelledby=\"accordion-tab-5-heading-3\" data-parent=\"#accordion-tab-5\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>We can\'t compete with Mom! Her company is big and evil! Ours is small and neutral! Look, everyone wants to be like Germany, but do we really have the pure strength of \'will\'? I just told you! You\'ve killed me!</p>\r\n                                            <p><strong>Example: </strong>But, like most politicians, he promised more than he could deliver.</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-5-heading-4\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-5-content-4\" aria-expanded=\"false\" aria-controls=\"accordion-tab-5-content-4\">And until then, I can never die?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-5-content-4\" aria-labelledby=\"accordion-tab-5-heading-4\" data-parent=\"#accordion-tab-5\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>I don\'t know what you did, Fry, but once again, you screwed up! Now all the planets are gonna start cracking wise about our mamas. Well, let\'s just dump it in the sewer and say we delivered it.</p>\r\n                                            <p><strong>Example: </strong>Have you ever tried just turning off the TV, sitting down with your children, and hitting them? Hey, tell me something. You\'ve got all this money. How come you always dress like you\'re doing your laundry?</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"tab-pane\" id=\"tab6\" role=\"tabpanel\" aria-labelledby=\"tab6\">\r\n                            <div class=\"accordion\" id=\"accordion-tab-6\">\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-6-heading-1\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-6-content-1\" aria-expanded=\"false\" aria-controls=\"accordion-tab-6-content-1\">Doomsday device?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse \" id=\"accordion-tab-6-content-1\" aria-labelledby=\"accordion-tab-6-heading-1\" data-parent=\"#accordion-tab-6\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>Ah, now the ball\'s in Farnsworth\'s court! We\'ll need to have a look inside you with this camera. Stop it, stop it. It\'s fine. I will \'destroy\' you! Bender! Ship! Stop bickering or I\'m going to come back there and change your opinions manually!</p>\r\n                                            <p><strong>Example: </strong>So I really am important? How I feel when I\'m drunk is correct?</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-6-heading-2\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-6-content-2\" aria-expanded=\"false\" aria-controls=\"accordion-tab-6-content-2\">And so we say goodbye to our beloved pet, Nibbler?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-6-content-2\" aria-labelledby=\"accordion-tab-6-heading-2\" data-parent=\"#accordion-tab-6\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>Nibbler, who\'s gone to a place where I, too, hope one day to go. The toilet. But existing is basically all I do! I suppose I could part with \'one\' and still be feared. I just told you! You\'ve killed me!</p>\r\n                                            <p><strong>Example: </strong>What\'s with you kids? Every other day it\'s food, food, food.</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-6-heading-3\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-6-content-3\" aria-expanded=\"false\" aria-controls=\"accordion-tab-6-content-3\">Tell her you just want to talk?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-6-content-3\" aria-labelledby=\"accordion-tab-6-heading-3\" data-parent=\"#accordion-tab-6\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>It has nothing to do with mating. Soon enough. There, now he\'s trapped in a book I wrote: a crummy world of plot holes and spelling errors! Daylight and everything. Hey! I\'m a porno-dealing monster, what do I care what you think?</p>\r\n                                            <p><strong>Example: </strong>Is that a cooking show? It doesn\'t look so shiny to me. And why did \'I\' have to take a cab?</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"card\">\r\n                                    <div class=\"card-header\" id=\"accordion-tab-6-heading-4\">\r\n                                        <h5>\r\n                                            <button class=\"btn btn-link\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-6-content-4\" aria-expanded=\"false\" aria-controls=\"accordion-tab-6-content-4\">Good man. Nixon\'s pro-war and pro-family?</button>\r\n                                        </h5>\r\n                                    </div>\r\n                                    <div class=\"collapse\" id=\"accordion-tab-6-content-4\" aria-labelledby=\"accordion-tab-6-heading-4\" data-parent=\"#accordion-tab-6\">\r\n                                        <div class=\"faq-body\">\r\n                                            <p>I don\'t \'need\' to drink. I can quit anytime I want! THE BIG BRAIN AM WINNING AGAIN! I AM THE GREETEST! NOW I AM LEAVING EARTH, FOR NO RAISEN! There\'s one way and only one way to determine if an animal is intelligent. Dissect its brain!</p>\r\n                                            <p><strong>Example: </strong>Guess again. Yeah, I do that with my stupidness. And when we woke up, we had these bodies.</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div> -->\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n', 1, 2, 8, 1, 1, 1, 1725602972, 1, 1734000206, 0, 0, 0, 1725602940, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1);
INSERT INTO `modx_site_content` (`id`, `type`, `pagetitle`, `longtitle`, `description`, `alias`, `link_attributes`, `published`, `pub_date`, `unpub_date`, `parent`, `isfolder`, `introtext`, `content`, `richtext`, `template`, `menuindex`, `searchable`, `cacheable`, `createdby`, `createdon`, `editedby`, `editedon`, `deleted`, `deletedon`, `deletedby`, `publishedon`, `publishedby`, `menutitle`, `donthit`, `privateweb`, `privatemgr`, `content_dispo`, `hidemenu`, `class_key`, `context_key`, `content_type`, `uri`, `uri_override`, `hide_children_in_tree`, `show_in_tree`, `properties`, `alias_visible`) VALUES
(11, 'document', 'wedding', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '\r\n \r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/breadcrumb/sr_bc_rentacar.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n        <div class=\"overlay\"></div>\r\n        <div class=\"container\">\r\n          <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Transfer</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Transfer<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n          </div>\r\n        </div>\r\n        </section>\r\n      \r\n      \r\n      \r\n        <section class=\"about-section\">\r\n        <div class=\"container\">\r\n          <div class=\"row clearfix\">\r\n            \r\n           <!--Content Column-->\r\n           <div class=\"content-column col-md-6 col-sm-12 col-xs-12\">\r\n            <div class=\"inner-column\">\r\n                <div class=\"sec-title\">\r\n                    <h2 style=\"font-size: 30px; color: #a40000; font-weight: bold;\">Enjoy a Smooth Journey</h2>\r\n                </div>\r\n                <div class=\"text\" style=\"text-align: justify;\">\r\n                    Enhance your Sri Lankan experience with SR Rent A Car\'s premium chauffeur-driven airport and hotel transfers. Our fleet of luxurious vehicles, coupled with our professional and experienced chauffeurs, ensures a comfortable and stylish travel experience.\r\n                </div>\r\n                <div class=\"text\" style=\"text-align: justify;\">\r\n                    From the moment you land at Colombo International Airport (CMB), our Meet and Greet service welcomes you with a warm and efficient reception. Our drivers will escort you to your chosen vehicle and assist you throughout your journey.\r\n                </div>\r\n                <div class=\"text\" style=\"text-align: justify;\">\r\n                    Whether you\'re heading to your hotel or embarking on a sightseeing adventure, our reliable and punctual transfer services provide the freedom and convenience you need. Book your airport transfer with SR Rent A Car today and experience the difference.\r\n                </div>\r\n                            \r\n        \r\n                <a href=\"[[~16]]\" class=\"theme-btn btn-style-three\">Book a Transfer</a>\r\n            </div>\r\n        </div>\r\n        \r\n      \r\n            \r\n            <!--Image Column-->\r\n            <div class=\"image-column col-md-6 col-sm-12 col-xs-12\">\r\n              <div class=\"inner-column \" data-wow-delay=\"0ms\" data-wow-duration=\"1500ms\">\r\n                <div class=\"image\">\r\n                  <img src=\"assets/images/wedding/transfer.jpg\" alt=\"\">\r\n                  <div class=\"overlay-box\">\r\n                    <div class=\"year-box\"><span class=\"number\">20</span>Years <br> industry  <br> Expertise</div>\r\n                  </div>\r\n                </div>\r\n              </div>\r\n            </div>\r\n            \r\n          </div>\r\n        </div>\r\n      </section>\r\n      \r\n      \r\n      \r\n        \r\n      <!-- Topic Cards -->\r\n      <div id=\"cards_landscape_wrap-2\" >\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n      <div class=\"container\">\r\n\r\n        \r\n        <div class=\"col-12\">\r\n           \r\n            <div class=\"text\" style=\"text-align: justify;\">\r\n                <strong>1. Seamless Airport Transfers</strong><br>\r\n                Arrive in style and comfort with our 24/7 private airport transfer service. Our experienced chauffeur will greet you at Bandaranaike International Airport (CMB) with a personalized sign and escort you directly to your destination.\r\n            </div>\r\n            <div class=\"text\" style=\"text-align: justify;\">\r\n                <strong>2. Hassle-Free Hotel Transfers</strong><br>\r\n                Already in Sri Lanka? Let us take care of your transportation needs. Book a hotel transfer and enjoy a smooth ride to your next destination. Our chauffeur will pick you up right from your hotel doorstep.\r\n            </div>\r\n              </div>\r\n        <h1 class=\"text-gradient\" style=\"font-size: 30px;text-align: left;\">Our Transfer Services</h1>\r\n        \r\n        <!-- Full-width paragraph -->\r\n        <div class=\"col-12\">\r\n          <p style=\"text-align: justify; font-size: 18px; margin-bottom: 30px;\">\r\n            SR Rent A Car offers chauffeur-driven Airport Transfers and Hotel Transfers in Sri Lanka. We offer our service for Colombo International Airport (CMB) & all hotels in Sri Lanka. Our helpful chauffeurs and the luxury fleet will ensure you get a professional luxury service. Our well-maintained luxurious vehicle fleet allows you to choose your specific vehicle category from our vehicle fleet. You can also contact our helpful staff members 24/7 to clarify any information.\r\n          </p>\r\n      \r\n          <p style=\"text-align: justify; font-size: 18px; margin-bottom: 30px;\">\r\n            We provide efficient and reliable airport transfers in Sri Lanka. We take pride in our Meet and Greet Service from the Colombo International Airport (CMB). On arrival, you will meet one of our professional and experienced chauffeurs. He’ll escort you to your car and will kindly assist you throughout your journey. Our extravagant chauffeur-driven car will transport you to your desired location. \r\n          </p>\r\n      \r\n          <p style=\"text-align: justify; font-size: 18px; margin-bottom: 30px;\">\r\n            SR Rent A Car offers a stylish and comfortable journey without relying on the public transportation system. It provides opportunities for flexibility to explore places of your choice right from the airport. A single phone call or email will have your airport transfer luxury vehicle ready to collect you from your home, office or airport. We take pride in offering the best of luxury cars and chauffeur driven car hire services for airport transfers. If you’re looking for reliable chauffeur service and to be transported in safety, comfort and style, book your airport car rental with SR Rent A Car today!\r\n          </p>\r\n        </div>\r\n        \r\n        \r\n      \r\n      \r\n        <div class=\"container\">\r\n          \r\n  <div class=\"social-box\">\r\n    <div class=\"container\">\r\n       <div class=\"row\">\r\n        <div class=\"col-lg-6 col-xs-12  text-center\" >\r\n          <div class=\"box\" style=\"border: 3px solid #007bff; border-radius: 5px; margin-bottom: 10px;height: 380px;\" >\r\n            \r\n            <div class=\"box-title\">\r\n              <h3>Airport Transfers</h3>\r\n            </div>\r\n                      <div class=\"panel-body\">\r\n              <div class=\"col-md-12\">\r\n                <p class=\"disclosure\" style=\"text-align: justify;\">SR Transfers can arrange airport transfers from Bandaranaike International Airport (Colombo Airport [CMB]) to many destinations in Sri Lanka. We provide a 24/7 private airport transfer service catering to all your requirements. Our chauffeur will greet you at the Colombo airport with a paging board with your name on it at the arrival lobby.</p>\r\n                <a href=\"about.html\" class=\"theme-btn btn-style-three\" style=\"margin-left: 35px;\">(+94) 773 207 108</a>\r\n              </div>\r\n            </div>\r\n           </div>\r\n        </div>	\r\n        <div class=\"col-lg-6 col-xs-12 text-center\">\r\n          <div class=\"box\" style=\"border: 3px solid #007bff; border-radius: 5px; margin-bottom: 10px;height: 380px;\">\r\n                 \r\n            <div class=\"box-title\">\r\n              <h3>Hotel Transfers</h3>\r\n            </div>\r\n                      <div class=\"panel-body\">\r\n       \r\n           \r\n              <div class=\"col-md-12\">\r\n                <p class=\"disclosure\" style=\"text-align: justify;\">If you are already in the country and need secure transportation to move among destinations, you can book a transfer from SR Transfers. We’ll send a chauffeur-driven to your hotel doorstep to pick you up.</p>\r\n                <a href=\"[~30]]\" class=\"theme-btn btn-style-three\" style=\"margin-left: 35px;\">(+94) 773 207 108</a>\r\n              </div>\r\n              </div>\r\n           </div>\r\n        </div>	 \r\n  \r\n         \r\n        \r\n      \r\n       \r\n      \r\n       \r\n    </div>		\r\n    </div>\r\n  </div>\r\n      \r\n            \r\n    <!-- Team -->\r\n    \r\n    <!-- Team -->\r\n    <section id=\"team\" class=\"pb-5\">\r\n      <div class=\"container\">\r\n          <div class=\"row\">\r\n              <!-- Team member -->\r\n              <div class=\"col-12 col-sm-6 col-lg-4 mb-4\">\r\n                  <div class=\"transfercard\">\r\n                      <div class=\"transfercard-body text-center\">\r\n                          <h1 class=\"card__header\">\r\n                              <i class=\"fas fa-briefcase\"></i> Highly Professional Services\r\n                          </h1>\r\n                          <p class=\"card-text text-start\">\r\n                              We provide exceptional, exquisite transfer services to all our customers visiting or leaving Sri Lanka. \r\n                              Our outstanding and affordable Sri Lanka private transfers are fast, reliable, comfortable, and convenient.\r\n                          </p>\r\n                      </div>\r\n                  </div>\r\n              </div>\r\n              <!-- ./Team member -->\r\n              \r\n              <!-- Team member -->\r\n              <div class=\"col-12 col-sm-6 col-lg-4 mb-4\">\r\n                  <div class=\"transfercard\">\r\n                      <div class=\"transfercard-body text-center\">\r\n                          <h1 class=\"card__header\">\r\n                              <i class=\"fas fa-star\"></i> Quality Customer Services\r\n                          </h1>\r\n                          <p class=\"card-text text-start\">\r\n                              At SR Transfers, customer satisfaction is our priority. We ensure a smooth, comfortable, \r\n                              and stress-free experience with top-class services tailored to your needs.\r\n                          </p>\r\n                      </div>\r\n                  </div>\r\n              </div>\r\n              <!-- ./Team member -->\r\n  \r\n              <!-- Team member -->\r\n              <div class=\"col-12 col-sm-6 col-lg-4 mb-4\">\r\n                  <div class=\"transfercard\">\r\n                      <div class=\"transfercard-body text-center\">\r\n                          <h1 class=\"card__header\">\r\n                              <i class=\"fas fa-clock\"></i> Reliable Services\r\n                          </h1>\r\n                          <p class=\"card-text text-start\">\r\n                              We understand the importance of time. Our transfer services are punctual, prompt, \r\n                              and reliable. Our team monitors flight arrivals to ensure timely pickups without delays.\r\n                          </p>\r\n                      </div>\r\n                  </div>\r\n              </div>\r\n              <!-- ./Team member -->\r\n  \r\n              <!-- Team member -->\r\n              <div class=\"col-12 col-sm-6 col-lg-4 mb-4\">\r\n                  <div class=\"transfercard\">\r\n                      <div class=\"transfercard-body text-center\">\r\n                          <h1 class=\"card__header\">\r\n                              <i class=\"fas fa-users\"></i> Well Trained Team\r\n                          </h1>\r\n                          <p class=\"card-text text-start\">\r\n                              Our professional drivers have extensive knowledge of Colombo and other popular cities in Sri Lanka, \r\n                              ensuring a smooth and enjoyable journey for you.\r\n                          </p>\r\n                      </div>\r\n                  </div>\r\n              </div>\r\n              <!-- ./Team member -->\r\n  \r\n              <!-- Team member -->\r\n              <div class=\"col-12 col-sm-6 col-lg-4 mb-4\">\r\n                  <div class=\"transfercard\">\r\n                      <div class=\"transfercard-body text-center\">\r\n                          <h1 class=\"card__header\">\r\n                              <i class=\"fas fa-shield-alt\"></i> High Safety Concerns\r\n                          </h1>\r\n                          <p class=\"card-text text-start\">\r\n                              Your safety is our priority. We ensure secure, well-maintained vehicles and highly trained drivers for a safe and stress-free journey.\r\n                          </p>\r\n                      </div>\r\n                  </div>\r\n              </div>\r\n              <!-- ./Team member -->\r\n  \r\n              <!-- Team member -->\r\n              <div class=\"col-12 col-sm-6 col-lg-4 mb-4\">\r\n                  <div class=\"transfercard\">\r\n                      <div class=\"transfercard-body text-center\">\r\n                          <h1 class=\"card__header\">\r\n                              <i class=\"fas fa-clock\"></i> 24/7 Availability\r\n                          </h1>\r\n                          <p class=\"card-text text-start\">\r\n                              We offer 24/7 transfer services, ensuring that we are available at any time, even on weekends and public holidays.\r\n                          </p>\r\n                      </div>\r\n                  </div>\r\n              </div>\r\n              <!-- ./Team member -->\r\n          </div>\r\n      </div>\r\n  </section>\r\n  \r\n    <!-- Team -->\r\n    <!-- Team -->\r\n              \r\n              \r\n      \r\n      \r\n       \r\n          </div>\r\n          \r\n          \r\n           \r\n        \r\n        </div>\r\n      \r\n         \r\n      \r\n   \r\n      \r\n      ', 1, 2, 9, 1, 1, 1, 1725626063, 1, 1740034570, 0, 0, 0, 1725626040, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1),
(12, 'document', 'Valid Driving Licenses To Rent A Car In Sri Lanka', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '<section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n  <div class=\"overlay\"></div>\r\n  <div class=\"container\">\r\n    <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n      <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n        <h1 class=\"mb-2 bread\">Blog</h1>\r\n        <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\">\r\n          <span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span>\r\n          <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span>\r\n        </p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"ftco-section\">\r\n  <div class=\"container\">\r\n    <div class=\"row\">\r\n      <div class=\"col-lg-8 ftco-animate\">\r\n        <h2 class=\"mb-3\" style=\"font-weight: 900;\">Valid Driving Licenses To Rent A Car In Sri Lanka</h2>\r\n        <p>\r\n          <img src=\"assets/images/blog/driving_license.jpg\" alt=\"\" class=\"img-fluid\">\r\n        </p>\r\n        <p style=\"text-align: justify;\">\r\n          Are you a tourist who is planning to go on a road trip to Sri Lanka? Or are planning to stay in Sri Lanka as a long-stay tourist? On both occasions, you might need to rent a car to fulfil your travel needs. To do so, you need to get a valid driving licence. Because it’s the only proof to let others know that you have the necessary qualifications to drive a motor vehicle.\r\n        </p>\r\n        <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">What are the valid Driving Licences in Sri Lanka?</h3>\r\n        <ul style=\"text-align: justify;\">\r\n          <li><strong>International Driving Permit (IDP) plus the local endorsement.</strong></li>\r\n          <li><strong>Temporary Sri Lankan Driving Licence. (TSDL)</strong></li>\r\n          <li><strong>Regular Sri Lankan Driving Licence.</strong></li>\r\n        </ul>\r\n\r\n        <p style=\"text-align: justify;\">\r\n          Let’s take a short moment and have a look at the above driving licence. You can obtain any of the above licences by yourself by visiting relevant offices.\r\n        </p>\r\n\r\n        <div class=\"bordered-text\">\r\n          If you need a hassle-free process to get your driving licence to rent a car in Sri Lanka; SR RENT A CAR can arrange everything\r\n          and have it ready before you arrive to pick up your vehicle. All you have to do is send the relevant documents for us at least\r\n          one week in advance.\r\n        </div>\r\n\r\n        <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">How to get an International Driving Permit (IDP) Endorsement?</h3>\r\n        \r\n        <p style=\"text-align: justify;\">\r\n          An International Driving Permit (IDP) also known as International Driving Licence (IDL) allows its holder to drive a private motor vehicle outside his/her country. But it’s not accepted in the country which issues the permit. There are three types of IDPs in the world.\r\n        </p>\r\n        <ul style=\"text-align: justify;\">\r\n          <li><strong>IDP’s issued under the 1926 convention.</strong></li>\r\n          <li><strong>IDP’s issued under the 1949 convention.</strong></li>\r\n          <li><strong>IDP’s issued under the 1968 convention.</strong></li>\r\n        </ul>\r\n        \r\n        <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">Loolecondera Estate: Birthplace of Ceylon Tea</h3>\r\n\r\n        <p style=\"text-align: justify;\">\r\n          Though there are some countries like China where any IDP will not be recognised. Sri Lanka recognised all types of IDPs. But, we are one of the few countries that require you to get your IDP verified (endorsed) by a local authority before you can drive a motor vehicle. The Automobile Association (AA) of Ceylon is the authorised organization to issue endorsements for your IDP. You have to visit the AA office in Colombo and physically submit the following documentation to AA to get the endorsement.\r\n        </p>\r\n\r\n        <ul style=\"text-align: justify;\">\r\n          <li><strong>Clear scan copy of your IDP. (front side & inner photo attached page)</strong></li>\r\n          <li><strong>Clear scan copy of your passport.</strong></li>\r\n          <li><strong>A clear passport-size photograph of yourself.</strong></li>\r\n        </ul>\r\n        \r\n        <p style=\"text-align: justify;\">It’ll take several days to get the endorsement based on the time and date you visit their office.</p>\r\n        <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">How to get a Temporary Sri Lankan Driving Licence (TSDL)?</h3>\r\n        \r\n        <p style=\"text-align: justify;\">\r\n          Temporary Sri Lankan Driving Licence (TSDL) can be obtained only for light vehicle categories. A foreigner can get in a TDL without any restrictions other than the vehicle category. As the name “temporary”, this licence is only valid for a short period (one month to six months depending on the vehicle category you required). To obtain a TDL, you have to visit the Department of Motor Vehicles (DMV) in Werahara (1h drive from Central Colombo) in person and hand over the following documents.\r\n        </p>\r\n        <ul style=\"text-align: justify;\">\r\n          <li><strong>Clear scan copy of your country licence. (front and back)</strong></li>\r\n          <li><strong>Clear scan copy of your passport.</strong></li>\r\n          <li><strong>A clear passport-size photograph of yourself.</strong></li>\r\n        </ul>\r\n        <p style=\"text-align: justify;\">Though it won’t take very long to get a TDL, the hassle you have to go through may not be worth it if you are in the country for a short holiday.</p>\r\n        \r\n        <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">How to get a Sri Lankan Driving Licence?</h3>\r\n        \r\n        <p style=\"text-align: justify;\">\r\n          Sri Lankan Driving Licence is available to all Sri Lankan residents. (Including dual visa holders) Tourists who are staying for more than six months with their visas can also apply for it. By visiting the DMV head office or any other regional office you can get the licence. But obtaining the licence has a lengthy process and will take several days (maybe weeks) to get it.\r\n        </p>\r\n\r\n        <div class=\"bordered-text\">\r\n          If your licence (country licence or the IDP) is in a language other than English, you will have to get it translated by your own country’s embassy or a professional translator (sworn translator) in your country.\r\n        </div>\r\n\r\n        <p style=\"text-align: justify;\">\r\n          We hope now you have a clear knowledge of the Driving Licence a foreigner must have to rent a car in Sri Lanka. If you have more questions, you can contact us through our hotline at +94 777 780 729 (WhatsApp) or email at info@srilankarentacar.com.\r\n        </p>\r\n      </div> <!-- .col-md-8 -->\r\n\r\n      <div class=\"col-lg-4 sidebar ftco-animate\">\r\n        <div class=\"sidebar-box ftco-animate\">\r\n          <h3>Previous Blogs</h3>\r\n          <div class=\"block-21 mb-4 d-flex\">\r\n            <a class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/hidden_gems.jpg);\"></a>\r\n            <div class=\"text\">\r\n              <h3 class=\"heading\"><a href=\"[[~8]]\">Hidden Gems near Kandy to Discover with Your Rental Car</a></h3>\r\n              <div class=\"meta\">\r\n                <div><a href=\"[[~8]]\"><span class=\"icon-calendar\"></span> Sep 20, 2023</a></div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n          <div class=\"block-21 mb-4 d-flex\">\r\n            <a class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/driving_license.jpg);\"></a>\r\n            <div class=\"text\">\r\n              <h3 class=\"heading\"><a href=\"[[~12]]\">Valid Driving Licenses To Rent A Car In Sri Lanka</a></h3>\r\n              <div class=\"meta\">\r\n                <div><a href=\"[[~12]]\"><span class=\"icon-calendar\"></span> Nov 01, 2021</a></div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n          <div class=\"block-21 mb-4 d-flex\">\r\n            <a class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/road_sign.jpg);\"></a>\r\n            <div class=\"text\">\r\n              <h3 class=\"heading\"><a href=\"[[~13]]\">Essential Guide to Sri Lanka’s Traffic Rules for Drivers</a></h3>\r\n              <div class=\"meta\">\r\n                <div><a href=\"[[~13]]\"><span class=\"icon-calendar\"></span> Oct 27, 2021</a></div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n          <div class=\"block-21 mb-4 d-flex\">\r\n            <a class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/drive_road.jpg);\"></a>\r\n            <div class=\"text\">\r\n              <h3 class=\"heading\"><a href=\"[[~14]]\">How to travel in Sri Lanka at your own pace?</a></h3>\r\n              <div class=\"meta\">\r\n                <div><a href=\"[[~14]]\"><span class=\"icon-calendar\"></span> Apr 19, 2024</a></div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n          <div class=\"block-21 mb-4 d-flex\">\r\n            <a class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/short_term.jpg);\"></a>\r\n            <div class=\"text\">\r\n              <h3 class=\"heading\"><a href=\"[[~15]]\">How to Rent a Car in Sri Lanka: The Step-by-Step Process</a></h3>\r\n              <div class=\"meta\">\r\n                <div><a href=\"[[~15]]\"><span class=\"icon-calendar\"></span> Jun 21, 2021</a></div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div><!-- END COL -->\r\n    </div>\r\n  </div>\r\n</section>\r\n', 1, 2, 10, 1, 1, 1, 1725744932, 1, 1728024971, 0, 0, 0, 1725744900, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1),
(13, 'document', 'traffic_guide', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '  \r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n      <div class=\"overlay\"></div>\r\n      <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Blog</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n        \r\n        <section class=\"ftco-section\">\r\n            <div class=\"container\">\r\n                <div class=\"row\">\r\n          <div class=\"col-lg-9 ftco-animate\">\r\n            <h2 class=\"mb-3\" style=\"font-weight: 900;\">Essential Guide to Sri Lanka’s Traffic Rules for Drivers</h2>\r\n            <img src=\"assets/images/blog/road_sign.jpg\" alt=\"\" class=\"img-fluid\">\r\n           \r\n            <p>\r\n            </p>\r\n            <p style=\"text-align: justify;\">\r\n              If you’re planning a trip to Sri Lanka and want to explore the country at your own pace, renting a car is the best option, especially if you plan to visit off-the-beaten-path destinations. However, it’s important to have a basic knowledge of Sri Lanka’s traffic rules in order to have the best possible travel experience with your rental vehicle. To help you get started, we’ve put together this guide to the most important traffic rules and signs in Sri Lanka.\r\n              </p>\r\n              <h2 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">Traffic Rules in Sri Lanka For Drivers</h2>\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">01. Speed limit</h3>\r\n            \r\n              \r\n              <p style=\"text-align: justify;\">\r\n                Speed limits are put in place to keep drivers and pedestrians safe. It is important to follow these limits, as driving too fast can result in accidents and fatalities. Be mindful of speed limits, especially in residential areas, school zones, and other areas where there are likely to be pedestrians. If there are no signs or markings, stick to the general speed limit. Here are the speed limits in Sri Lanka:\r\n              </p>\r\n              <ul>\r\n                <li>The speed limit in urban areas is 0-50 km/h.</li>\r\n                <li>The speed limit in rural areas is 0-70 km/h (This limit depends on the area. So make sure to pay close attention to the given limit by the side of the road).</li>\r\n                <li>The speed limit on a highway is 80-100 km/h (If you are not within the given speed limit on a highway, you’ll be fined when you exit the highway).</li>\r\n            </ul>\r\n            <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\"> 02. Don’t Drive Under the Influence of Drugs or Alcohol</h3>\r\n              \r\n            <ul>\r\n              <li>Driving under the influence of alcohol or drugs is illegal in Sri Lanka. Not only is it illegal, but it is also extremely dangerous.</li>\r\n              <li>If you are taking medication that may affect your ability to drive, make sure to check with your doctor before getting behind the wheel.</li>\r\n              <li>If you plan to drink or take special medications, make sure to arrange for a designated driver or use public transportation to get home.</li>\r\n              <li>Violating this rule can lead to severe penalties under the Sri Lanka Motor Traffic Law.</li>\r\n              <li>The speed limit in urban areas is 0-50 km/h.</li>\r\n              <li>The speed limit in rural areas is 0-70 km/h (This limit depends on the area. So make sure to pay close attention to the given limit by the side of the road).</li>\r\n              <li>The speed limit on a highway is 80-100 km/h (If you are not within the given speed limit on a highway, you’ll be fined when you exit the highway).</li>\r\n          </ul>\r\n          \r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\"> 03. Avoid Using Mobile Phones </h3>\r\n              <ul>\r\n                  <li> Using mobile phones while driving is dangerous and can result in accidents. </li>\r\n                  <li> It is illegal to use a mobile phone while driving in Sri Lanka, so make sure to avoid this temptation. </li>\r\n                  <li>If you need to make a call or send a text message, pull over to a safe location.</li>\r\n              </ul>\r\n              \r\n              \r\n              \r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">04. Road signs</h3>\r\n              <ul>\r\n                <li> \r\n                  You must always follow the road signs accordingly. Failing to do so may harm you or your vehicle or pedestrians or a third party. In the worst-case scenario, above all or some of them together may happen.\r\n              </li>\r\n              </ul>\r\n                  \r\n                </p>\r\n              <p style=\"text-align: justify;\">\r\n                  Ramboda Falls, situated approximately 20 kilometres from Kandy, ranks among Sri Lanka’s most magnificent waterfalls. The journey itself is a visual treat as you meander through picturesque tea plantations. Upon arrival, a short walk leads you to the base of the falls, where you can feel the mist on your skin and witness the sheer might of nature. It’s an ideal place for a refreshing interlude.\r\n              </p>\r\n                            \r\n        \r\n<div class=\"row\">\r\n          <div class=\"image-row\">\r\n            <img src=\"assets/images/blog/news/road_sign/1.jpg\" alt=\"image-row\">\r\n            <img src=\"assets/images/blog/news/road_sign/2.jpg\" alt=\"image-row\">\r\n            <img src=\"assets/images/blog/news/road_sign/3.jpg\" alt=\"image-row\">\r\n         \r\n            \r\n        </div>\r\n        <div class=\"image-row\">\r\n          <img src=\"assets/images/blog/news/road_sign/4.jpg\" alt=\"image-row\">\r\n          <img src=\"assets/images/blog/news/road_sign/5.jpg\" alt=\"image-row\">\r\n          <img src=\"assets/images/blog/news/road_sign/6.jpg\" alt=\"image-row\">\r\n          \r\n          \r\n      </div>\r\n      <div class=\"image-row\">\r\n        <img src=\"assets/images/blog/news/road_sign/7.jpg\" alt=\"image-row\">\r\n        <img src=\"assets/images/blog/news/road_sign/8.jpg\" alt=\"image-row\">\r\n        <img src=\"assets/images/blog/news/road_sign/9.jpg\" alt=\"image-row\">\r\n           \r\n    </div>\r\n    <div class=\"image-row\">\r\n      <img src=\"assets/images/blog/news/road_sign/10.jpg\" alt=\"image-row\">\r\n      <img src=\"assets/images/blog/news/road_sign/11.jpg\" alt=\"image-row\">\r\n      <img src=\"assets/images/blog/news/road_sign/12.jpg\" alt=\"image-row\">\r\n         \r\n  </div>\r\n      </div>\r\n        </p>\r\n\r\n        <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">  05. Traffic lights</h3>\r\n        <h4>Traffic Signal Guidelines in Sri Lanka</h4>\r\n        <p>Traffic signals are put in place to control the flow of traffic and ensure safety on the roads. It is important to obey these signals, as they help prevent accidents and keep traffic moving smoothly.</p>\r\n        \r\n        <ul>\r\n            <li><strong>Red Light:</strong> Always means “stop.” If you’re facing a red light, wait for it to turn green.</li>\r\n            <li><strong>Both Red & Yellow:</strong> Get ready to move forward.</li>\r\n            <li><strong>Yellow:</strong> Slow down and prepare to stop.</li>\r\n            <li><strong>Flashing Yellow:</strong> Slow down and proceed with caution.</li>\r\n            <li><strong>Green:</strong> You can go.</li>\r\n            <li><strong>Green Arrow:</strong> You can turn only in the direction indicated by the arrow.</li>\r\n        </ul>\r\n        \r\n        <p>If traffic lights and traffic police are present, follow the signs given by the police officer.</p>\r\n\r\n             \r\n        <div class=\"row\">\r\n          <div class=\"image-row\">\r\n            <img src=\"assets/images/blog/news/road_sign/13.jpg\" alt=\"image-row\">\r\n            <img src=\"assets/images/blog/news/road_sign/14.jpg\" alt=\"image-row\">\r\n            <img src=\"assets/images/blog/news/road_sign/15.jpg\" alt=\"image-row\">\r\n         \r\n            \r\n        </div>\r\n        <div class=\"image-row\">\r\n          <img src=\"assets/images/blog/news/road_sign/16.jpg\" alt=\"image-row\">\r\n          <img src=\"assets/images/blog/news/road_sign/17.jpg\" alt=\"image-row\">\r\n          <img src=\"assets/images/blog/news/road_sign/18.jpg\" alt=\"image-row\">\r\n          \r\n          \r\n      </div>\r\n   \r\n      </div>\r\n        \r\n              \r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">07. Keep Left</h3>\r\n              <ul><li>Indicators are used to signal your intentions to other drivers. When you are turning or changing lanes, make sure to use your indicators to let other drivers know what you are doing. This will help prevent accidents and ensure that traffic flows smoothly.</li></ul>\r\n              <p></p>\r\n\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">08. Use Indicators</h3>\r\n              <ul><li>In Sri Lanka, drivers and cyclists are required to drive on the left side of the road. This is because most vehicles in Sri Lanka are right-hand drives. Keeping left is not only a legal requirement, but it also helps to prevent accidents and keep traffic moving smoothly.</li></ul>\r\n              <p></p>\r\n\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">09. Keep a Safe Distance</h3>\r\n              <ul>\r\n                <li>Maintaining a safe distance between your vehicle and the vehicle in front of you is important to prevent accidents.</li>\r\n                <li> If the vehicle in front of you suddenly stops or slows down, you need to have enough time to react and avoid a collision.</li>\r\n                <li> The recommended distance is at least two seconds behind the vehicle in front of you.</li>\r\n              </ul>\r\n              <p></p>\r\n              \r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">10. Give Way to Pedestrians</h3>\r\n              <ul>\r\n                <li>Pedestrians have the right of way in Sri Lanka, especially at zebra crossings and other designated pedestrian crossings.</li>\r\n                <li>It is important to give way to pedestrians, as they are more vulnerable than drivers and may not be able to react quickly enough to avoid an accident.</li>\r\n               \r\n    \r\n                <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">11. Keep Your Vehicle Roadworthy</h3>\r\n                <ul>\r\n                  <li>Keeping your vehicle in good condition is important to ensure safety on the roads. Regular maintenance, such as oil changes, tire rotations, and brake checks, can help prevent accidents and keep your vehicle running smoothly.</li>\r\n                  <li>    Make sure to also check your lights, signals, and brakes before you start driving.</li>\r\n                  <li> At SR Rent A Car, we make sure all vehicles in our fleet are roadworthy with regular vehicle checkups.</li>\r\n                  <li>  We advise you to do a daily morning check on the vehicle during your rental period in order to avoid surprises.\r\n                  </li>\r\n                 \r\n                  <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">12. Follow Lane Discipline</h3>\r\n                  <ul>\r\n                    <li>    Lane discipline is important to keep traffic moving smoothly and to prevent accidents.</li>\r\n                    <li>    When driving on multi-lane roads, keep to the left lane unless overtaking.</li>\r\n                    <li>  Use the right lane only when overtaking and return to the left lane once you have passed the vehicle in front of you.</li>\r\n                    <li>  Avoid zig-zagging between lanes as it can confuse other drivers and cause accidents.\r\n                    </li>\r\n\r\n                    <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">13. Use Headlights Properly</h3>\r\n                    <ul>\r\n                      <li>   Headlights are an important safety feature of your vehicle.</li>\r\n                      <li>   \r\n                        Use your headlights during the day in low-light conditions or when visibility is poor due to weather conditions such as fog, rain or mist.</li>\r\n                      <li> When driving at night, use your headlights on the high beam only when there is no oncoming traffic or when overtaking.</li>\r\n                      <li> Switch to low beam when you see oncoming traffic to avoid dazzling other drivers.\r\n                      </li>\r\n      \r\n                      \r\n                      <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">14. Give Way to Emergency Vehicles</h3>\r\n                      <ul>\r\n                        <li>  \r\n                          When you hear sirens or see flashing lights of an ambulance, fire truck or police vehicle, move to the side of the road and give them the right of way.\r\n                      </li>\r\n                        <li>   \r\n                        \r\n                          This helps emergency vehicles reach their destination faster and saves lives.</li>\r\n                       \r\n                          \r\n                      <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">14. Give Way to Emergency Vehicles</h3>\r\n                      <ul>\r\n                        <li>  \r\n                          When you hear sirens or see flashing lights of an ambulance, fire truck or police vehicle, move to the side of the road and give them the right of way.\r\n                      </li>\r\n                        <li>   \r\n                        \r\n                          This helps emergency vehicles reach their destination faster and saves lives.</li>\r\n\r\n                          <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">15. Yield to Vehicles on Your Right</h3>\r\n                          <ul>\r\n                            <li>  \r\n                              When approaching an intersection or roundabout, yield to vehicles on your right.\r\n                          </li>\r\n                          <li>  \r\n                            If two vehicles approach the intersection at the same time, the vehicle on the right has the right of way.\r\n                        </li>\r\n                        <li>  \r\n                          Make sure to come to a complete stop at stop signs and only proceed when it is safe to do so.\r\n                      </li>\r\n                           \r\n                       \r\n                      <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">16. Avoid Blocking Intersections</h3>\r\n                      <ul>\r\n                        <li>  \r\n                          Blocking intersections or crossroads is illegal in Sri Lanka and can result in a fine.\r\n                      </li>\r\n                      <li>  \r\n                        If you are approaching an intersection and the traffic is backed up, wait until there is enough space for you to pass through before entering the intersection.\r\n                    </li>\r\n                    <li>  \r\n                      This helps prevent gridlock and ensures that emergency vehicles can pass through if necessary.\r\n                  </li>\r\n                       \r\n                                     \r\n                  <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">17. Don’t Use Horns Unnecessarily</h3>\r\n                  <ul>\r\n                    <li>  \r\n                      Horns should only be used to warn other drivers of your presence or to alert them of imminent danger.\r\n                  </li>\r\n                  <li>  \r\n                    Honking your horn unnecessarily can be annoying and distracting to other drivers and pedestrians.\r\n                </li>\r\n                <li>  \r\n                  It is also illegal to use horns in some specific locations.\r\n              </li>\r\n\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">18. Give Way to heavy vehicles</h3>\r\n              <ul>\r\n                <li>  \r\n                  Heavy vehicles like buses and lorries are a common sight on Sri Lankan roads, and it is important to give them plenty of space. Buses have the right of way when pulling out from a bus stop, so make sure to yield to them.\r\n              </li>\r\n      \r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">19. Watch Out for Motorcycles</h3>\r\n              <ul>\r\n                <li>  \r\n                  Motorcycles are a common mode of transportation in Sri Lanka, and they can be difficult to see on the road. Always check your blind spots before changing lanes or turning, and give motorcycles plenty of space.\r\n              </li>\r\n\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">20. Don’t Park Illegally</h3>\r\n              <ul>\r\n                <li>  \r\n                  Illegal parking can cause traffic congestion and make it difficult for other drivers to navigate the roads. Make sure to park only in designated parking areas, and avoid blocking driveways or entrances.\r\n              </li>\r\n\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">21. Watch Out for Animals</h3>\r\n              <ul>\r\n                <li>  \r\n                  Animals, such as cows and dogs, can sometimes wander onto Sri Lankan roads. Always be on the lookout for animals, especially in rural areas, and slow down if necessary to avoid hitting them.\r\n              </li>\r\n\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">22. Have a Valid Driving License</h3>\r\n              <ul>\r\n                <li>  \r\n                  All who drive a motor vehicle in Sri Lanka must have a valid driving license on public roads. It is illegal to go without a license, and doing so can result in fines, imprisonment, or other penalties.\r\n              </li>\r\n              <li>  \r\n                If you are a foreigner and thinking about whether your licence is acceptable in Sri Lanka to drive a motor vehicle, read our complete license requirement guide.\r\n            </li>\r\n        \r\n            <p style=\"text-align: justify;\">In conclusion, these are some of the basic traffic rules that every driver in Sri Lanka should know. By obeying these rules, you can help prevent accidents, reduce traffic congestion, and ensure safety on the roads. Remember to always drive safely, and stay alert while on the road.</p>\r\n                     \r\n                         \r\n    \r\n              \r\n    \r\n    \r\n  \r\n\r\n                  \r\n                 \r\n              \r\n                       \r\n                             \r\n                              \r\n                          \r\n    \r\n\r\n                  \r\n                    \r\n\r\n   \r\n  \r\n    \r\n\r\n\r\n\r\n   \r\n  \r\n\r\n\r\n\r\n\r\n              \r\n            \r\n\r\n\r\n\r\n\r\n\r\n          </div> <!-- .col-md-8 -->\r\n\r\n          <div class=\"col-lg-3 sidebar ftco-animate\">\r\n            <div class=\"sidebar-box ftco-animate\">\r\n                <h3>Previous Blogs</h3>\r\n                \r\n                <div class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~7]]\" class=\"d-flex\">\r\n                        <div class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/hidden_gems.jpg);\"></div>\r\n                        <div class=\"text\">\r\n                            <h3 class=\"heading\">Hidden Gems near Kandy to Discover with Your Rental Car</h3>\r\n                            <div class=\"meta\">\r\n                                <div><span class=\"icon-calendar\"></span> Sep 20, 2023</div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n                \r\n                <div class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~12]]\" class=\"d-flex\">\r\n                        <div class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/driving_license.jpg);\"></div>\r\n                        <div class=\"text\">\r\n                            <h3 class=\"heading\">Valid Driving Licenses To Rent A Car In Sri Lanka</h3>\r\n                            <div class=\"meta\">\r\n                                <div><span class=\"icon-calendar\"></span> Nov 01, 2021</div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n        \r\n                <div class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~14]]\" class=\"d-flex\">\r\n                        <div class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/drive_road.jpg);\"></div>\r\n                        <div class=\"text\">\r\n                            <h3 class=\"heading\">How to travel in Sri Lanka at your own pace?</h3>\r\n                            <div class=\"meta\">\r\n                                <div><span class=\"icon-calendar\"></span> Apr 19, 2024</div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n        \r\n                <div class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~15]]\" class=\"d-flex\">\r\n                        <div class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/short_term.jpg);\"></div>\r\n                        <div class=\"text\">\r\n                            <h3 class=\"heading\">How to Rent a Car in Sri Lanka: The Step-by-Step Process</h3>\r\n                            <div class=\"meta\">\r\n                                <div><span class=\"icon-calendar\"></span> Jun 21, 2021</div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n        \r\n            </div>\r\n        </div><!-- END COL -->\r\n        \r\n            </div>\r\n        </section>\r\n        \r\n    ', 1, 2, 11, 1, 1, 1, 1726211301, 1, 1728023055, 0, 0, 0, 1726211280, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1);
