(14, 'document', 'How to travel in Sri Lanka at your own pace', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '  \r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n      <div class=\"overlay\"></div>\r\n      <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Blog</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n        \r\n        <section class=\"ftco-section\">\r\n            <div class=\"container\">\r\n                <div class=\"row\">\r\n          <div class=\"col-lg-9 ftco-animate\">\r\n            <h2 class=\"mb-3\" style=\"font-weight: 900;\">How to travel in Sri Lanka at your own pace?</h2>\r\n            <img src=\"assets/images/blog/drive_road.jpg\" alt=\"\" class=\"img-fluid\">\r\n           \r\n            <p>\r\n            </p>\r\n            <p style=\"text-align: justify;\">\r\n              If you are thinking about travelling to Sri Lanka, you must plan how you are going to move around the country. If you are a free-spirited person who likes to travel at your own pace and without restrictions you might be thinking, that you have several options.\r\n              </p>\r\n            <ul><li>\r\n              01. Use public transportations (Busses & Trains)\r\n            \r\n            </li>\r\n          <li>  02. Rent a private vehicle</li\r\n            ></ul>\r\n\r\n            <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">Use public transportations (Busses & Trains)</h3>\r\n              <p style=\"text-align: justify;\">\r\n                Using public transportations are the cheapest method to travel within Sri Lanka. But it has lots of downfalls.\r\n              </p>\r\n\r\n              <h4 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">Rent a private vehicle</h4>\r\n              <p style=\"text-align: justify;\">In Sri Lanka, you can rent a vehicle in a few different ways.</p>\r\n              <ul>\r\n                <li style=\"text-align: justify;\"><strong>Rent a Third-Party Verified Private Taxi:</strong> \r\n                    If you are familiar with using the Uber mobile app, you will find it’s very much available to use in Sri Lanka. It’s the cheapest private transportation method you’ll find in Sri Lanka. However, its availability is limited to city areas in the country. Some drivers may even cancel the ride refusing to travel to specific locations.\r\n                </li>\r\n                <p></p>\r\n                <li style=\"text-align: justify;\"><strong>Rent a Private Tuk-Tuk:</strong> \r\n                    When you are out on the road, you can see small three-wheelers ready to take you anywhere you need to go. The availability of these is very high in Sri Lanka. Even though they lack space and comfort, they can get the job done if you are not traveling with a group or if you have lots of luggage.\r\n                </li>\r\n                <p></p>\r\n                <li style=\"text-align: justify;\"><strong>Rent a Car from a Car Rental Company:</strong> \r\n                    Finally, you can rent vehicles from car rental companies such as SR Rent A Car. Unlike other transportation methods where you’re just a passenger, renting a vehicle gives you the option to drive yourself if you prefer. This flexibility allows you to move around the country at your own pace. Rental companies offer a range of vehicles to choose from, and daily or monthly rental fees vary depending on your choice of vehicle. Additionally, you can book your vehicle even before you visit the country.\r\n                </li>\r\n            </ul>\r\n    \r\n  \r\n\r\n                  \r\n                 \r\n              \r\n                       \r\n                             \r\n                              \r\n                          \r\n    \r\n\r\n                  \r\n                    \r\n\r\n   \r\n  \r\n    \r\n\r\n\r\n\r\n   \r\n  \r\n\r\n\r\n\r\n\r\n              \r\n            \r\n\r\n\r\n\r\n\r\n\r\n          </div> <!-- .col-md-8 -->\r\n          <div class=\"col-lg-3 sidebar ftco-animate\">\r\n            <div class=\"sidebar-box ftco-animate\">\r\n                <h3>Previous Blogs</h3>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~7]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/hidden_gems.jpg);\" alt=\"Hidden Gems near Kandy\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~7]]\">Hidden Gems near Kandy to Discover with Your Rental Car</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~7]]\"><span class=\"icon-calendar\"></span> September 20, 2023</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~12]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/driving_license.jpg);\" alt=\"Driving License\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~12]]\">Valid Driving Licenses To Rent A Car In Sri Lanka</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~12]]\"><span class=\"icon-calendar\"></span> November 1, 2021</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~13]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/road_sign.jpg);\" alt=\"Traffic Rules\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~13]]\">Essential Guide to Sri Lanka’s Traffic Rules for Drivers</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~13]]\"><span class=\"icon-calendar\"></span> October 27, 2021</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~14]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/drive_road.jpg);\" alt=\"Travel in Sri Lanka\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~14]]\">How to travel in Sri Lanka at your own pace?</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~14]]\"><span class=\"icon-calendar\"></span> April 19, 2024</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~15]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/short_term.jpg);\" alt=\"Rent a Car\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~15]]\">How to Rent a Car in Sri Lanka: The Step-by-Step Process</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~15]]\"><span class=\"icon-calendar\"></span> June 21, 2021</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n            </div>\r\n        </div><!-- END COL -->\r\n        \r\n            </div>\r\n        </section>\r\n        \r\n    ', 1, 2, 12, 1, 1, 1, 1726214455, 1, 1728023697, 0, 0, 0, 1726214400, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1),
(15, 'document', 'How to Rent a Car in Sri Lanka', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '  \r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n      <div class=\"overlay\"></div>\r\n      <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Blog</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n        \r\n        <section class=\"ftco-section\">\r\n            <div class=\"container\">\r\n                <div class=\"row\">\r\n          <div class=\"col-lg-9 ftco-animate\">\r\n            <h2 class=\"mb-3\" style=\"font-weight: 900;\">How to Rent a Car in Sri Lanka: The Step-by-Step Process</h2>\r\n            <img src=\"assets/images/blog/short_term.jpg\" alt=\"\" class=\"img-fluid\">\r\n           \r\n            <p>\r\n            </p>\r\n            <p style=\"text-align: justify;\">\r\n              Thinking about renting a car in Sri Lanka? Take a look at everything you need to know about the car hire process, so you can feel at ease with your rental experience at SR Rent A Car Sri Lanka.\r\n              </p>\r\n    \r\n              <h4 style=\"font-weight: 700px;\">Rent a car process in Sri Lanka</h4>\r\n\r\n            \r\n              <ol><li>You must have a valid driver’s license.</li>\r\n                <li>You must submit a copy of your valid passport.</li>\r\n                <li>Verify your age.</li>\r\n                <li>Select the vehicle of your choice.</li>\r\n                <li>Submit valid payment method.</li>\r\n                <li>Inspect your vehicle when pickup.</li>\r\n                <li>Return your vehicle on time</li>\r\n              \r\n              </ol>\r\n    \r\n              <h2 class=\"mb-3\" style=\"font-weight: 900;\">You must have a valid driver’s license.</h2>\r\n\r\n              <p style=\"text-align: justify;\">If you think you can rent a car in Sri Lanka if you have a valid international driver’s license, you are wrong. According to Sri Lankan law, people who have valid Sri Lankan driver’s licenses can drive a vehicle in Sri Lanka. If you are a Sri Lankan citizen or hold dual citizenship with a Sri Lankan driver’s license you are good to go. If you are not a Sri Lankan citizen, you must have 2 documents with you to drive around Sri Lanka by yourself.</p>\r\n\r\n              <ol><li>International Driving License</li>\r\n              <li> Sri Lanka Driving License (issued by Automobile Association of Ceylon)</li>\r\n              \r\n              </ol>\r\n              <img src=\"assets/images/blog/driving_license.jpg\" alt=\"\" class=\"img-fluid\">\r\n\r\n              <p style=\"text-align: justify;\">Read our article on <a href=\"\r\n                \">“Driver’s License Requirement To Rent A Car In Sri Lanka”</a> to learn more about license requirements.</p>\r\n             \r\n                <h2 class=\"mb-3\" style=\"font-weight: 900;\">You must submit a copy of your valid passport.</h2>\r\n\r\n                <p style=\"text-align: justify;\"> You must have your valid passport with you every time drive in Sri Lanka. Mainly because it is a legitimate document that can prove your identity where ever you go in Sri Lanka.</p>\r\n\r\n                <h2 class=\"mb-3\" style=\"font-weight: 900;\">Verify your age</h2>\r\n\r\n                <p style=\"text-align: justify;\">If you are planning to drive a vehicle in Sri Lanka, you need to wait until you are 18 years or above. But, to rent a vehicle in Sri Lanka you must be at least 21 years old. We advise people who are above the age of 75 not to drive even though he/she has an international drivers license. If you insist, you can drive a vehicle we recommend you take extra precautions when you drive in Sri Lanka.</p>\r\n\r\n                <h2 class=\"mb-3\" style=\"font-weight: 900;\">Select the vehicle of your choice</h2>\r\n\r\n                <p style=\"text-align: justify;\">SR Rent A Car has a wide variety of vehicles you can choose from. Keep your budget and driving style in mind before selecting the right vehicle for you.</p>\r\n                <h2 class=\"mb-3\" style=\"font-weight: 900;\">Submit valid payment method</h2>\r\n\r\n                <p style=\"text-align: justify;\">Credit cards are the only accepted payment forms by us. We ask you to leave a deposit for security purposes. Deposit value may vary based on the vehicle you choose to rent.</p>\r\n\r\n                <h2 class=\"mb-3\" style=\"font-weight: 900;\">Inspect your vehicle when pickup</h2>\r\n\r\n                <p style=\"text-align: justify;\">We highly recommend you inspect the vehicle you have been given. After the inspection, you have to submit a signed document to verify that you have been given a properly functional vehicle in excellent condition. Based on this document, we’ll inspect your vehicle when you return it.</p>\r\n\r\n                <h2 class=\"mb-3\" style=\"font-weight: 900;\">Return your vehicle on time</h2>\r\n\r\n                <p style=\"text-align: justify;\">We are a 24/7 open car rental company. Therefore you’ll have no problem with open hours when returning the vehicle. We’ll give you some flexible hours when returning. But if the return day exceeds, you’ll be charged for the extra day(s).</p>\r\n\r\n                  \r\n                 \r\n              \r\n                       \r\n                             \r\n                              \r\n                          \r\n    \r\n\r\n                  \r\n                    \r\n\r\n   \r\n  \r\n    \r\n\r\n\r\n\r\n   \r\n  \r\n\r\n\r\n\r\n\r\n              \r\n            \r\n\r\n\r\n\r\n\r\n\r\n          </div> <!-- .col-md-8 -->\r\n          <div class=\"col-lg-3 sidebar ftco-animate\">\r\n            <div class=\"sidebar-box ftco-animate\">\r\n                <h3>Previous Blogs</h3>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~7]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/hidden_gems.jpg);\" alt=\"Hidden Gems near Kandy\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~7]]\">Hidden Gems near Kandy to Discover with Your Rental Car</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~7]]\"><span class=\"icon-calendar\"></span> September 20, 2023</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~12]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/driving_license.jpg);\" alt=\"Driving License\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~12]]\">Valid Driving Licenses To Rent A Car In Sri Lanka</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~12]]\"><span class=\"icon-calendar\"></span> November 1, 2021</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~13]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/road_sign.jpg);\" alt=\"Traffic Rules\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~13]]\">Essential Guide to Sri Lanka’s Traffic Rules for Drivers</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~13]]\"><span class=\"icon-calendar\"></span> October 27, 2021</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~14]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/drive_road.jpg);\" alt=\"Travel in Sri Lanka\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~14]]\">How to travel in Sri Lanka at your own pace?</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~14]]\"><span class=\"icon-calendar\"></span> April 19, 2024</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n                <article class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~15]]\" class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/short_term.jpg);\" alt=\"Rent a Car\"></a>\r\n                    <div class=\"text\">\r\n                        <h3 class=\"heading\"><a href=\"[[~15]]\">How to Rent a Car in Sri Lanka: The Step-by-Step Process</a></h3>\r\n                        <div class=\"meta\">\r\n                            <div><a href=\"[[~15]]\"><span class=\"icon-calendar\"></span> June 21, 2021</a></div>\r\n                        </div>\r\n                    </div>\r\n                </article>\r\n        \r\n            </div>\r\n        </div><!-- END COL -->\r\n        \r\n        </section>\r\n        \r\n    ', 1, 2, 13, 1, 1, 1, 1726215527, 1, 1728023819, 0, 0, 0, 1726215480, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1),
(16, 'document', 'registration', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '  \r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/breadcrumb/sr_bc_fleet.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n		<div class=\"overlay\"></div>\r\n		<div class=\"container\">\r\n		  <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n			<div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n			  <h1 class=\"mb-2 bread\">Reserve A Car</h1>\r\n			  <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Reserve A Car<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n			</div>\r\n		  </div>\r\n		</div>\r\n	  </section>\r\n\r\n	  <section class=\"ftco-section ftco-no-pt ftco-no-pb\">\r\n		<div class=\"container-fluid px-0\">\r\n           \r\n		  <div class=\"row d-flex no-gutters\">\r\n			<div class=\"col-md-12 order-md-last ftco-animate makereservation p-4 p-md-5 pt-5\">\r\n				<h3 id=\"carName\" class=\"text-center\"><P>You Selected</P></h3>\r\n			  <div class=\"py-md-5\">\r\n				<form action=\"#\">\r\n				  <div class=\"row\">\r\n					<div class=\"col-md-6\">\r\n					  <div class=\"form-group\">\r\n						<label for=\"\">Your Name</label>\r\n						<input type=\"text\" class=\"form-control\" placeholder=\"Your Name\">\r\n					  </div>\r\n					</div>\r\n					<div class=\"col-md-6\">\r\n					  <div class=\"form-group\">\r\n						<label for=\"\">Your email address</label>\r\n						<input type=\"text\" class=\"form-control\" placeholder=\"Your Email\">\r\n					  </div>\r\n					</div>\r\n					<div class=\"col-md-6\">\r\n						\r\n						<div class=\"form-group\">\r\n						  <label for=\"country-code\">Your contact number</label>\r\n						  <div class=\"input-group\">\r\n							<select id=\"country-code\" class=\"form-control\">\r\n								<option value=\"+1\">USA (+1)</option>\r\n							