			  \r\n					<div class=\"col-md-12\">\r\n					  <div class=\"form-group\">\r\n						<label for=\"\">What kind of support do you want?</label>\r\n						<div class=\"select-wrap one-third\">\r\n						  <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n						  <select id=\"supportType\" class=\"form-control\" onchange=\"updateLabels()\">\r\n							<option value=\"\" selected>Please Choose an Option</option>\r\n							<option value=\"rent-a-car\">Rent A Car</option>\r\n							<option value=\"airport-hotel-transfer\">Airport & Hotel Transfer</option>\r\n							<option value=\"wedding-car-rentals\">Wedding Car Rentals</option>\r\n						  </select>\r\n						</div>\r\n					  </div>\r\n					</div>\r\n					<div class=\"col-md-12\" id=\"dynamicLabels\"></div>\r\n					<div class=\"col-md-12 mt-3\">\r\n					  <div class=\"form-group\">\r\n                        <input type=\"text\" name=\"car_code\" id=\"selectedCarCode\">\r\n						<input type=\"submit\" value=\"Make a Reservation\" class=\"theme-btn btn-style-three\">\r\n					  </div>\r\n					</div>\r\n				  </div>\r\n				</form>\r\n			  </div>\r\n			</div>\r\n		  </div>\r\n		</div>\r\n	  </section>\r\n	  \r\n\r\n\r\n\r\n		  <script>function updateLabels() {\r\n			const select = document.getElementById(\'supportType\');\r\n			const dynamicLabels = document.getElementById(\'dynamicLabels\');\r\n			const value = select.value;\r\n		  \r\n			let labels = \'\';\r\n		  \r\n			switch (value) {\r\n			  case \'rent-a-car\':\r\n				labels = `\r\n				<div class=\"col-md-12\">\r\n					 <div class=\"row\">\r\n						<div class=\"col-md-6\">\r\n				 <div class=\"form-group\">\r\n						<label for=\"\">Vehicle Pickup Location </label>\r\n						<div class=\"select-wrap one-third\">\r\n						  <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n						  <select id=\"supportType\" class=\"form-control\">\r\n							<option value=\"\"selected >Colombo International Airport (CMB)</option>\r\n							<option value=\"\">SR  Rent A Car Office Seeduwa</option>\r\n							<option value=\"\">Colombo Hotel</option>\r\n							<option value=\"\">Negombo Hotel</option>\r\n							<option value=\"\">Beruwala Hotel</option>\r\n							<option value=\"\">Benthota Hotel</option>\r\n							<option value=\"\">Galle Hotel</option>\r\n							<option value=\"\">Kandy Hotel</option>\r\n							<option value=\"\">Nuwara Eliya Hotel</option>\r\n							<option value=\"\">Jaffna Hotel</option>\r\n							<option value=\"\">Other Locations</option>\r\n						  </select>\r\n						</div>\r\n					  </div>\r\n					  </div>\r\n					 \r\n\r\n					  <div class=\"col-md-6\">\r\n				 <div class=\"form-group\">\r\n						<label for=\"\">Vehicle Drop Off Location </label>\r\n						<div class=\"select-wrap one-third\">\r\n						  <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n						  <select id=\"supportType\" class=\"form-control\">\r\n							<option value=\"\"selected >SR  Rent A Car Office Seeduwa</option>\r\n							<option value=\"\" >Colombo International Airport (CMB)</option>\r\n							<option value=\"\">Colombo Hotel</option>\r\n							<option value=\"\">Negombo Hotel</option>\r\n							<option value=\"\">Beruwala Hotel</option>\r\n							<option value=\"\">Benthota Hotel</option>\r\n							<option value=\"\">Galle Hotel</option>\r\n							<option value=\"\">Kandy Hotel</option>\r\n							<option value=\"\">Nuwara Eliya Hotel</option>\r\n							<option value=\"\">Jaffna Hotel</option>\r\n							<option value=\"\">Other Locations</option>\r\n							\r\n						  </select>\r\n						</div>\r\n					  </div>\r\n					  </div>\r\n\r\n\r\n				   </div>\r\n				   </div>\r\n\r\n				\r\n<div class=\"col-md-12\">\r\n    <div class=\"row\">\r\n        <div class=\"col-md-6\">\r\n            <div class=\"form-group\">\r\n                <label for=\"vehicleType\">Preferred Vehicle Type</label>\r\n                <div class=\"select-wrap one-third\">\r\n                    <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n                    <select id=\"vehicleType\" class=\"form-control\" onchange=\"updateBrands()\">\r\n                        <option value=\"mini\">Mini Cars</option>\r\n                        <option value=\"economy\">Economy Cars</option>\r\n                        <option value=\"standard\">Standard Cars</option>\r\n                        <option value=\"semi-executive\">Semi Executive Cars</option>\r\n                        <option value=\"executive\">Executive Cars</option>\r\n                        <option value=\"luxury\">Luxury Cars</option>\r\n                        <option value=\"mini-suv\">Mini SUVs (4 X 4)</option>\r\n                        <option value=\"large-suv\">Large SUVs (4 X 4)</option>\r\n                        <option value=\"mini-van\">Mini Van</option>\r\n						<option value=\"van\">Van</option>\r\n                        <option value=\"bus\">Luxury Coach</option>\r\n						<option value=\"long_bus\">Super Luxury Coach</option>\r\n                    </select>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <div class=\"col-md-6\">\r\n            <div class=\"form-group\">\r\n                <label for=\"vehicleBrand\">Preferred Vehicle Brand</label>\r\n                <div class=\"select-wrap one-third\">\r\n                    <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n                    <select id=\"vehicleBrand\" class=\"form-control\">\r\n                        <option value=\"\">Select a vehicle type first</option>\r\n                    </select>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>\r\n				 \r\n\r\n\r\n             <div class=\"col-md-12\">\r\n					 <div class=\"row\">\r\n					  <div class=\"col-md-6\">\r\n    <div class=\"form-group\">\r\n        <label for=\"pickupdate\">Pickup Date & Time</label>\r\n        <input type=\"datetime-local\" class=\"form-control\" id=\"pickupdate\" placeholder=\"Pickup Date & Time\">\r\n    </div>\r\n</div>\r\n\r\n <div class=\"col-md-6\">\r\n    <div class=\"form-group\">\r\n        <label for=\"dropoffdate\">Dropoff Date & Time</label>\r\n        <input type=\"datetime-local\" class=\"form-control\" id=\"dropoffdate\" placeholder=\"Dropoff Date & Time\">\r\n    </div>\r\n</div>\r\n\r\n\r\n				   </div>\r\n				   </div>\r\n             </div>\r\n				   </div>\r\n\r\n				   					<div class=\"col-md-12\">\r\n						<div class=\"row\">\r\n							<div class=\"col-md-6\">\r\n					  <div class=\"form-group\">\r\n						<label for=\"\">I need a Sri Lanka Driver\'s License</label>\r\n						<div class=\"select-wrap one-third\">\r\n						  <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n						  <select id=\"supportType\" class=\"form-control\" onchange=\"updateLabels()\">\r\n							<option value=\"\" selected>Please Choose an Option</option>\r\n							<option value=\"license\">Yes</option>\r\n							<option value=\"\">No</option>\r\n						  </select>\r\n						</div>\r\n					  </div>\r\n					</div>\r\n					</div>\r\n				</div>\r\n\r\n<div class=\"col-md-12\">\r\n	<label>Extras (subject to additional charges)</label><br>\r\n<div class=\"row\">\r\n\r\n  \r\n   </div>\r\n</div>\r\n				`;\r\n				break;\r\n			  case \'airport-hotel-transfer\':\r\n				labels = `\r\n				  <div class=\"col-md-6\">\r\n					<div class=\"form-group\">\r\n					  <label for=\"\">Flight Number</label>\r\n					  <input type=\"text\" class=\"form-control\" placeholder=\"Flight Number\">\r\n					</div>\r\n				  </div>\r\n				  <div class=\"col-md-6\">\r\n					<div class=\"form-group\">\r\n					  <label for=\"\">Arrival Time</label>\r\n					  <input type=\"text\" class=\"form-control\" placeholder=\"Arrival Time\">\r\n					</div>\r\n				  </div>\r\n				`;\r\n				break;\r\n			  case \'wedding-car-rentals\':\r\n				labels = `\r\n				  <div class=\"col-md-6\">\r\n					<div class=\"form-group\">\r\n					  <label for=\"\">Wedding Date</label>\r\n					  <input type=\"date\" class=\"form-control\" placeholder=\"Wedding Date\">\r\n					</div>\r\n				  </div>\r\n				  <div class=\"col-md-6\">\r\n					<div class=\"form-group\">\r\n					  <label for=\"\">Venue Address</label>\r\n					  <input type=\"text\" class=\"form-control\" placeholder=\"Venue Address\">\r\n					</div>\r\n				  </div>\r\n				`;\r\n				break;\r\n			  default:\r\n				labels = \'\';\r\n				break;\r\n			}\r\n		  \r\n			dynamicLabels.innerHTML = labels;\r\n		  }\r\n		  \r\n		  </script>\r\n\r\n<!--script>\r\n	const brandsByType = {\r\n    mini: [\'Suzuki Alto (Japan)\', \'Perodua Axia\', \'Suzuki Alto (Indian)\'],\r\n    economy: [\'Toyota Aqua\', \'Suzuki Swift\', \'Suzuki Hustler\', \'Suzuki Wagon R\'],\r\n    standard: [\'Perudua Bezza\', \'Honda Insight\', \'Nissan Sunny\', \'Kia Rio\',],\r\n    \'semi-executive\': [\'Toyota Corolla 121\', \'Toyota Belta\', \'Toyota Prius\', \'Honda Grace\'],\r\n    executive: [\'Toyota Corolla Axio\', \'Toyota Allion\'],\r\n    luxury: [\'Mercedes Benz S Class\', \'BMW 520d\', \'Jaguar XF\'],\r\n    \'mini-suv\': [\'Kia Sorento\', \'Hyundai Tucson\', \'Nissan X-Trail\'],\r\n    \'large-suv\': [\'Toyota Land Cruiser Prado V8\', \'Mitsubishi Montero\', \'Toyota Land Cruiser Prado V150\'],\r\n    \'mini-van\': [\'Nissan Vanette\', \'Nissan Caravan\'],\r\n	\'van\': [\'Toyota Hiace KDH\', \'Micro Tourer\'],\r\n    bus: [\'Toyota Coaster\'],\r\n	long_bus: [\'Scania\'],\r\n};\r\n\r\nfunction updateBrands() {\r\n    const vehicleType = document.getElementById(\'vehicleType\').value;\r\n    const vehicleBrandSelect = document.getElementById(\'vehicleBrand\');\r\n\r\n    // Clear the current options\r\n    vehicleBrandSelect.innerHTML = \'\';\r\n\r\n    // Add a default option\r\n    if (vehicleType === \'\') {\r\n        vehicleBrandSelect.innerHTML = \'<option value=\"\">Select a vehicle type first</option>\';\r\n        return;\r\n    }\r\n\r\n    // Populate brand options based on selected vehicle type\r\n    const brands = brandsByType[vehicleType];\r\n    brands.forEach(brand => {\r\n        const option = document.createElement(\'option\');\r\n        option.value = brand;\r\n        option.textContent = brand;\r\n        vehicleBrandSelect.appendChild(option);\r\n    });\r\n}\r\n\r\n</script>\r\n\r\n\r\n<script>\r\n  \r\n   document.addEventListener(\'DOMContentLoaded\', function() {\r\n    const selected = document.querySelector(\'.selected\');\r\n    const optionsContainer = document.querySelector(\'.options\');\r\n    const selectedFlag = document.getElementById(\'selected-country-flag\');\r\n    let selectedCarCode = localStorage.getItem(\'selected_car\');\r\n    let selectedCarName = localStorage.getItem(\'selected_car_name\');\r\n    $(\'#carName\').text(selectedCarName);\r\n\r\n    selected.addEventListener(\'click\', () => {\r\n        optionsContainer.style.display = optionsContainer.style.display === \'block\' ? \'none\' : \'block\';\r\n    });\r\n\r\n    optionsContainer.addEventListener(\'click\', (event) => {\r\n        if (event.target && event.target.matches(\'div\')) {\r\n            selectedFlag.src = event.target.getAttribute(\'data-flag\');\r\n            selected.querySelector(\'span\').textContent = event.target.textContent;\r\n            selected.setAttribute(\'data-value\', event.target.getAttribute(\'data-value\'));\r\n            optionsContainer.style.display = \'none\';\r\n        }\r\n    });\r\n\r\n    document.addEventListener(\'click\', (event) => {\r\n        if (!selected.contains(event.target)) {\r\n            optionsContainer.style.display = \'none\';\r\n        }\r\n    });\r\n});\r\n\r\n\r\n</script>\r\n\r\n\r\n\r\n\r\n\r\n\r\n', 1, 2, 14, 1, 1, 1, 1726587393, 1, 1728905585, 1, 1728966131, 1, 1726587360, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1);
