  </div>\r\n                              </div>\r\n                          </div>\r\n                      </div>\r\n                      \r\n                      \r\n                      \r\n                      \r\n\r\n                      <div style=\"margin-bottom: 20px;\">\r\n                          <a href=\"[[~30]]\" class=\"theme-btn btn-style-three btn-selection\" data-carcode=\"car_025\"  data-carname=\"Toyota Land Cruiser V150 \" data-carimage=\"assets/images/reg/car_025.png\">Select</a>\r\n</div>\r\n                      \r\n                      \r\n                  </div>\r\n              </div>\r\n          </div>\r\n\r\n\r\n\r\n\r\n          \r\n\r\n\r\n\r\n          <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-6\">\r\n              <div class=\"card-flyer\" style=\"height: auto; overflow: hidden;\">\r\n                  <div class=\"text-box\" style=\"height: 100%;\">\r\n                      <!-- Exclusive Label -->\r\n                      <div class=\"exclusive-label\" style=\"position: absolute; top: 50px; right: 15px; background-color: #06b609; color: rgb(255, 255, 255); padding: 5px 10px; font-weight: bold; border-radius: 5px;\">\r\n                          Exclusive\r\n                      </div>\r\n                      <div class=\"image-box\" style=\"position: relative; display: inline-block;\">\r\n                          <img src=\"assets/images/car_booking/lsuv/montero_b.jpg\" alt=\"\" style=\"display: block; width: 100%; height: 200px;\" />\r\n                          <div class=\"overlay-text\" style=\"position: absolute; top: 10%; left: 65%; color: #fff7f7; font-size: 22px; text-align: center;\">\r\n                              <div class=\"icon-text\">\r\n                                  \r\n                                  <!-- <span>Per Day 75 <i class=\"fas fa-euro-sign\"></i></span> -->\r\n                              </div>\r\n                              \r\n                             \r\n                          </div>\r\n                          <div class=\"overlay-text\" style=\"position: absolute; top: 25%; left: 0%; color: white; font-size: 16px; text-align: center;\">\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-snowflake iconic\"></i>\r\n                                  <span>Front AC</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-users iconic\"></i>\r\n                                  <span>04 Max</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-suitcase iconic\"></i>\r\n                                  <span>04 Max</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-gas-pump iconic\"></i>\r\n                                  <span>Full to Full</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-tachometer iconic\"></i>\r\n                                  <span>150 KM per Day</span>\r\n                              </div>\r\n                          </div>\r\n                      </div>\r\n          \r\n                      <div class=\"text-container\">\r\n                          <h6 style=\"font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif; font-size: 18px;\">Mitsubishi Montero</h6>\r\n                          <p style=\"font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif; font-size: 14px; color: green;\">( Large SUVs (4 X 4) )</p>\r\n                          <div class=\"alert alert-info alert-dismissible\" role=\"alert\" style=\"background-color: #28a74609; color: rgb(132, 12, 12);\">\r\n                              <strong>Info:</strong> Flexible cancellation with every booking.\r\n                          </div>\r\n                      </div>\r\n          \r\n                      <div class=\"container\">\r\n                          <!-- Bootstrap Tabs -->\r\n                          <ul class=\"nav nav-tabs\" id=\"vehicleTab\" role=\"tablist\">\r\n                              <li class=\"nav-item\">\r\n                                  <a class=\"nav-link active\" id=\"details-tab\" data-toggle=\"tab\" href=\"#details2\" role=\"tab\" aria-controls=\"details\" aria-selected=\"true\">Basic Info</a>\r\n                              </li>\r\n                              <li class=\"nav-item\">\r\n                                  <a class=\"nav-link\" id=\"rates-tab\" data-toggle=\"tab\" href=\"#rates2\" role=\"tab\" aria-controls=\"rates\" aria-selected=\"false\">Rates</a>\r\n                              </li>\r\n                              <li class=\"nav-item\">\r\n                                  <a class=\"nav-link\" id=\"terms-tab\" data-toggle=\"tab\" href=\"#terms2\" role=\"tab\" aria-controls=\"terms\" aria-selected=\"false\">Terms & Conditions</a>\r\n                              </li>\r\n                          </ul>\r\n                          <div class=\"tab-content\" id=\"vehicleTabContent\">\r\n                              <div class=\"tab-pane fade show\" id=\"details2\" role=\"tabpanel\" aria-labelledby=\"details-tab\" style=\"padding: 15px;\">\r\n                                  <!-- Content for Basic Info -->\r\n                                  <h4>Driver & license requirements</h4>\r\n                                  <div style=\"text-align: left;\">\r\n                                      <p style=\"font-weight: 900;\">When you pick the car up, you\'ll need:</p>\r\n                                      <i class=\"fas fa-check-circle icon\"></i> Passport or national ID card<br>\r\n                                      <i class=\"fas fa-check-circle icon\"></i> Driving license<br>\r\n                                      <i class=\"fas fa-check-circle icon\"></i> Credit card\r\n                                  </div>\r\n                                  <hr>\r\n                                  <h4>Security deposit</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      At pick-up, the main driver will leave a refundable security deposit of $500.00 on their credit card. Cash and debit cards are not accepted. The counter staff will confirm how much this will be.\r\n                                  </p>\r\n                                  <hr>\r\n                                  <h4>Accepted cards</h4>\r\n                                  <div style=\"text-align: center;\">\r\n                                      <figure style=\"display: inline-block; margin: 10px;\">\r\n                                          <img src=\"assets/images/car_booking/master_card.png\" alt=\"Card Type 1\" style=\"width: 100px; height: auto;\">\r\n                                          <figcaption>Master Card</figcaption>\r\n                                      </figure>\r\n                                      <figure style=\"display: inline-block; margin: 10px;\">\r\n                                          <img src=\"assets/images/car_booking/visa_card.png\" alt=\"Card Type 2\" style=\"width: 100px; height: auto;\">\r\n                                          <figcaption>Visa Card</figcaption>\r\n                                      </figure>\r\n                                  </div>\r\n                                  <hr>\r\n                                  <h4>Damage Excess ($ 500)</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      If the car\'s bodywork gets damaged, the most you\'ll pay towards repairs covered by the Collision Damage Waiver is the damage excess ($500.00). This cover is only valid if you stick to the terms of the rental agreement.\r\n                                  </p>\r\n                                  <hr>\r\n                                  <h4>Mileage (Unlimited)</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      Your rental includes unlimited free kilometres.\r\n                                  </p>\r\n                                  <hr>\r\n                                  <h4>Fuel policy (Full to Full)</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      Your vehicle will be supplied with a full tank of fuel. To avoid incurring fuel charges, you will need to return it with the same amount of fuel as it had when you collected it.\r\n                                  </p>\r\n                                  <hr>\r\n                              </div>\r\n                              <div class=\"tab-pane fade\" id=\"rates2\" role=\"tabpanel\" aria-labelledby=\"rates-tab\">\r\n                                  <table class=\"table table-striped table-hover\">\r\n                                      <thead class=\"thead-light\">\r\n                                          <tr style=\"text-align: left;\">\r\n                                              <th>Duration</th>\r\n                                              <th>Rate</th>\r\n                                          </tr>\r\n                                      </thead>\r\n                                      <tbody style=\"text-align: left;\">\r\n                                          <tr class=\"table-primary\">\r\n                                              <td>01  - 03 Days</td>\r\n                                              <td>310 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-secondary\">\r\n                                              <td>04  - 06 Days</td>\r\n                                              <td>290 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-success\">\r\n                                              <td>07 Days</td>\r\n                                              <td>260 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-primary\">\r\n                                              <td>08  - 13 Days</td>\r\n                                              <td>230 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-secondary\">\r\n                                              <td>14 Days</td>\r\n                                              <td>210 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-success\">\r\n                                              <td>15 & More Days</td>\r\n                                              <td>190 Euro</td>\r\n                                          </tr>\r\n                                      </tbody>\r\n                                  </table>\r\n                              </div>\r\n                              <div class=\"tab-pane fade\" id=\"terms2\" role=\"tabpanel\" aria-labelledby=\"terms-tab\">\r\n                <div style=\"text-align: left; padding: 15px;\">\r\n                                                                             \r\n                                     \r\n                  <i class=\"fas fa-check-circle icon\"></i>Digital driving licences will not be accepted.\r\n                  <hr>\r\n                  <i class=\"fas fa-check-circle icon\"></i>The main driver or booking holder  must be in possession of a Credit Card in their own name when picking up the car.\r\n                  <hr>\r\n                  <i class=\"fas fa-check-circle icon\"></i>The driver must be within the age range of 21-65 years to be eligible to self drive.\r\n                  <hr>\r\n                  <i class=\"fas fa-check-circle icon\"></i>The renter must be physically present at the car pick up and on return of the vehicle.\r\n              </div>\r\n                              </div>\r\n                          </div>\r\n                      </div>\r\n          \r\n                      <div style=\"margin-bottom: 20px;\">\r\n                          <a href=\"[[~30]]\" class=\"theme-btn btn-style-three btn-selection\" data-carcode=\"car_026\"  data-carname=\"Mitsubishi Montero\" data-carimage=\"assets/images/reg/car_026.png\">Select</a>\r\n                      </div>\r\n                      \r\n                  </div>\r\n              </div>\r\n          </div>\r\n\r\n          \r\n\r\n\r\n\r\n\r\n\r\n          \r\n      </div>\r\n  </div>\r\n</div>\r\n\r\n<!-- Include Bootstrap JS and jQuery -->\r\n<script src=\"https://code.jquery.com/jquery-3.5.1.slim.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/bootstrap@4.5.2/dist/js/bootstrap.bundle.min.js\"></script>\r\n\r\n<script>\r\n  // JavaScript to handle tab collapse/expand\r\n  document.querySelectorAll(\'.nav-link\').forEach(tab => {\r\n      tab.addEventListener(\'click\', function() {\r\n          const targetId = this.getAttribute(\'href\');\r\n          const targetPane = document.querySelector(targetId);\r\n\r\n          // Toggle the collapse of the target tab pane\r\n          if (targetPane.classList.contains(\'show\')) {\r\n              targetPane.classList.remove(\'show\', \'active\'); // Collapse if already open\r\n          } else {\r\n              document.querySelectorAll(\'.tab-pane\').forEach(pane => {\r\n                  pane.classList.remove(\'show\', \'active\'); // Collapse all other tabs\r\n              });\r\n              targetPane.classList.add(\'show\', \'active\'); // Show the clicked tab\r\n          }\r\n      });\r\n  });\r\n\r\n  $(\'.btn-selection\').click(function(e){\r\n      let carCode = $(this).data(\'carcode\');\r\n      let carName = $(this).data(\'carname\');\r\n  let carImage = $(this).data(\'carimage\');\r\n      // console.log(\'selected_car_code\', carCode);\r\n      \r\n      localStorage.setItem(\'selected_car\', carCode);\r\n      localStorage.setItem(\'selected_car_name\', carName);\r\n  localStorage.setItem(\'selected_car_image\', carImage);\r\n\r\n  $(\'#carName\').html(`<img src=\"${carImage}\" alt=\"${carName}\" style=\"width: 50px; height: auto; vertical-align: middle;\"/> ${carName}`);\r\n  });\r\n\r\n\r\n\r\n  \r\ndocument.addEventListener(\"DOMContentLoaded\", () => {\r\n  fetch(\'fetch_rates.php\') // Adjust the endpoint to match your PHP script\r\n      .then(response => response.json())\r\n      .then(data => {\r\n          const tbody = document.querySelector(\'#rates2 table tbody\');\r\n          tbody.innerHTML = \'\'; // Clear existing rows\r\n\r\n          data.forEach((row, index) => {\r\n              const tr = document.createElement(\'tr\');\r\n              tr.className = index % 3 === 0 ? \'table-primary\' \r\n                         : index % 3 === 1 ? \'table-secondary\' \r\n                         : \'table-success\';\r\n\r\n              tr.innerHTML = `\r\n                  <td>${row.duration}</td>\r\n                  <td>${row.rate} Euro</td>\r\n              `;\r\n              tbody.appendChild(tr);\r\n          });\r\n      })\r\n      .catch(error => console.error(\'Error fetching data:\', error));\r\n});\r\n\r\n\r\n$(\'.btn-selection\').click(function(e){\r\n  let carCode = $(this).data(\'carcode\');\r\n  let carName = $(this).data(\'carname\');\r\n  let carImage = $(this).data(\'carimage\');\r\n  // console.log(\'selected_car_code\', carCode);\r\n  \r\n  localStorage.setItem(\'selected_car\', carCode);\r\n  localStorage.setItem(\'selected_car_name\', carName);\r\n  localStorage.setItem(\'selected_car_image\', carImage);\r\n\r\n  $(\'#carName\').html(`<img src=\"${carImage}\" alt=\"${carName}\" style=\"width: 50px; height: auto; vertical-align: middle;\"/> ${carName}`);\r\n});\r\n\r\n</script>\r\n\r\n</section>', 1, 2, 22, 1, 1, 1, 1727945198, 1, 1740029703, 0, 0, 0, 1727945160, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1);
INSERT INTO `modx_site_content` (`id`, `type`, `pagetitle`, `longtitle`, `description`, `alias`, `link_attributes`, `published`, `pub_date`, `unpub_date`, `parent`, `isfolder`, `introtext`, `content`, `richtext`, `template`, `menuindex`, `searchable`, `cacheable`, `createdby`, `createdon`, `editedby`, `editedon`, `deleted`, `deletedon`, `deletedby`, `publishedon`, `publishedby`, `menutitle`, `donthit`, `privateweb`, `privatemgr`, `content_dispo`, `hidemenu`, `class_key`, `context_key`, `content_type`, `uri`, `uri_override`, `hide_children_in_tree`, `show_in_tree`, `properties`, `alias_visible`) VALUES
(25, 'document', 'mvan', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '<section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/breadcrumb/sr_bc_rentacar.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n  <div class=\"overlay\"></div>\r\n  <div class=\"container\">\r\n      <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n              <h1 class=\"mb-2 bread\">MINI VAN</h1>\r\n              <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\">\r\n                  <span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span>\r\n                  <span class=\"mr-2\"><a href=\"[[~4]]\">Fleet <i class=\"ion-ios-arrow-forward\"></i></a></span>\r\n                  <span>MINI VAN<i class=\"ion-ios-arrow-forward\"></i></span>\r\n              </p>\r\n          </div>\r\n      </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- Topic Cards -->\r\n<div id=\"cards_landscape_wrap-2\"  style=\"padding-bottom: 50px;\">\r\n  <div class=\"container\">\r\n      <h5 class=\"text-fleet\" style=\"font-size: 25px; text-align: left;\">Which vehicle would you like to Drive?</h5>\r\n      <div class=\"row\">\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n          <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-6\">\r\n              <div class=\"card-flyer\" style=\"height: auto; overflow: hidden;\">\r\n                  <div class=\"text-box\" style=\"height: 100%;\">\r\n                      <!-- Exclusive Label -->\r\n                      <div class=\"exclusive-label\" style=\"position: absolute; top: 50px; right: 15px; background-color: #06b609; color: rgb(255, 255, 255); padding: 5px 10px; font-weight: bold; border-radius: 5px;\">\r\n                          Exclusive\r\n                      </div>\r\n                      <div class=\"image-box\" style=\"position: relative; display: inline-block;\">\r\n                          <img src=\"assets/images/car_booking/vans/caravan_b.jpg\" alt=\"\" style=\"display: block; width: 100%; height: 200px;\" />\r\n                          <div class=\"overlay-text\" style=\"position: absolute; top: 10%; left: 65%; color: #fff7f7; font-size: 22px; text-align: center;\">\r\n                              <div class=\"icon-text\">\r\n                                  \r\n                                  <!-- <span>Per Day 75 <i class=\"fas fa-euro-sign\"></i></span> -->\r\n                              </div>\r\n                              \r\n                             \r\n                          </div>\r\n                          <div class=\"overlay-text\" style=\"position: absolute; top: 25%; left: 0%; color: white; font-size: 16px; text-align: center;\">\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-snowflake iconic\"></i>\r\n                                  <span>Front AC</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-users iconic\"></i>\r\n                                  <span>04 Max</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-suitcase iconic\"></i>\r\n                                  <span>04 Max</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-gas-pump iconic\"></i>\r\n                                  <span>Full to Full</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-tachometer iconic\"></i>\r\n                                  <span>150 KM per Day</span>\r\n                              </div>\r\n                          </div>\r\n                      </div>\r\n          \r\n                      <div class=\"text-container\">\r\n                          <h6 style=\"font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif; font-size: 18px;\">Nissan Caravan</h6>\r\n                          <p style=\"font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif; font-size: 14px; color: green;\">( Mini Van )</p>\r\n                          <div class=\"alert alert-info alert-dismissible\" role=\"alert\" style=\"background-color: #28a74609; color: rgb(132, 12, 12);\">\r\n                              <strong>Info:</strong> Flexible cancellation with every booking.\r\n                          </div>\r\n                      </div>\r\n          \r\n                      <div class=\"container\">\r\n                          <!-- Bootstrap Tabs -->\r\n                          <ul class=\"nav nav-tabs\" id=\"vehicleTab\" role=\"tablist\">\r\n                              <li class=\"nav-item\">\r\n                                  <a class=\"nav-link active\" id=\"details-tab\" data-toggle=\"tab\" href=\"#details\" role=\"tab\" aria-controls=\"details\" aria-selected=\"true\">Basic Info</a>\r\n                              </li>\r\n                              <li class=\"nav-item\">\r\n                                  <a class=\"nav-link\" id=\"rates-tab\" data-toggle=\"tab\" href=\"#rates\" role=\"tab\" aria-controls=\"rates\" aria-selected=\"false\">Rates</a>\r\n                              </li>\r\n                              <li class=\"nav-item\">\r\n                                  <a class=\"nav-link\" id=\"terms-tab\" data-toggle=\"tab\" href=\"#terms\" role=\"tab\" aria-controls=\"terms\" aria-selected=\"false\">Terms & Conditions</a>\r\n                              </li>\r\n                          </ul>\r\n                          <div class=\"tab-content\" id=\"vehicleTabContent\">\r\n                              <div class=\"tab-pane fade show\" id=\"details\" role=\"tabpanel\" aria-labelledby=\"details-tab\" style=\"padding: 15px;\">\r\n                                  <div class=\"bordered-text\" style=\"font-size: 14px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">\r\n                                      At the car pickup, it is compulsory to hold a temporary Sri Lankan driver permit for self-driving.\r\n                                    \r\n                                    </div>\r\n                                  <!-- Content for Basic Info -->\r\n                                  <h4>Driver & license requirements</h4>\r\n                                  <div style=\"text-align: left;\">\r\n                                      <p style=\"font-weight: 900;\">When you pick the car up, you\'ll need:</p>\r\n                                      <i class=\"fas fa-check-circle icon\"></i> Passport or national ID card<br>\r\n                                      <i class=\"fas fa-check-circle icon\"></i> Driving license<br>\r\n                                      <i class=\"fas fa-check-circle icon\"></i> Credit card\r\n                                  </div>\r\n                                  <hr>\r\n                                  <h4>Security deposit</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      At pick-up, the main driver will leave a refundable security deposit of $500.00 on their credit card. Cash and debit cards are not accepted. The counter staff will confirm how much this will be.\r\n                                  </p>\r\n                                  <hr>\r\n                                  <h4>Accepted cards</h4>\r\n                                  <div style=\"text-align: center;\">\r\n                                      <figure style=\"display: inline-block; margin: 10px;\">\r\n                                          <img src=\"assets/images/car_booking/master_card.png\" alt=\"Card Type 1\" style=\"width: 100px; height: auto;\">\r\n                                          <figcaption>Master Card</figcaption>\r\n                                      </figure>\r\n                                      <figure style=\"display: inline-block; margin: 10px;\">\r\n                                          <img src=\"assets/images/car_booking/visa_card.png\" alt=\"Card Type 2\" style=\"width: 100px; height: auto;\">\r\n                                          <figcaption>Visa Card</figcaption>\r\n                                      </figure>\r\n                                  </div>\r\n                                  <hr>\r\n                                  <h4>Damage Excess ($ 500)</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      If the car\'s bodywork gets damaged, the most you\'ll pay towards repairs covered by the Collision Damage Waiver is the damage excess ($500.00). This cover is only valid if you stick to the terms of the rental agreement.\r\n                                  </p>\r\n                                  <hr>\r\n                                  <h4>Mileage (Unlimited)</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      Your rental includes unlimited free kilometres.\r\n                                  </p>\r\n                                  <hr>\r\n                                  <h4>Fuel policy (Full to Full)</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      Your vehicle will be supplied with a full tank of fuel. To avoid incurring fuel charges, you will need to return it with the same amount of fuel as it had when you collected it.\r\n                                  </p>\r\n                                  <hr>\r\n                              </div>\r\n                              <div class=\"tab-pane fade\" id=\"rates\" role=\"tabpanel\" aria-labelledby=\"rates-tab\">\r\n                                  <table class=\"table table-striped table-hover\">\r\n                                      <thead class=\"thead-light\">\r\n                                          <tr style=\"text-align: left;\">\r\n                                              <th>Duration</th>\r\n                                              <th>Rate</th>\r\n                                          </tr>\r\n                                      </thead>\r\n                                      <tbody style=\"text-align: left;\">\r\n                                          <tr class=\"table-primary\">\r\n                                              <td>01  - 03 Days</td>\r\n                                              <td>140 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-secondary\">\r\n                                              <td>04  - 06 Days</td>\r\n                                              <td>120 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-success\">\r\n                                              <td>07 Days</td>\r\n                                              <td>110 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-primary\">\r\n                                              <td>08  - 13 Days</td>\r\n                                              <td>100 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-secondary\">\r\n                                              <td>14 Days</td>\r\n                                              <td>95 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-success\">\r\n                                              <td>15 & More Days</td>\r\n                                              <td>90 Euro</td>\r\n                                          </tr>\r\n                                      </tbody>\r\n                                  </table>\r\n                              </div>\r\n                              <div class=\"tab-pane fade\" id=\"terms\" role=\"tabpanel\" aria-labelledby=\"terms-tab\">\r\n                <div style=\"text-align: left; padding: 15px;\">\r\n                                                                             \r\n                                     \r\n                  <i class=\"fas fa-check-circle icon\"></i>Digital driving licences will not be accepted.\r\n                  <hr>\r\n                  <i class=\"fas fa-check-circle icon\"></i>The main driver or booking holder  must be in possession of a Credit Card in their own name when picking up the car.\r\n                  <hr>\r\n                  <i class=\"fas fa-check-circle icon\"></i>The driver must be within the age range of 21-65 years to be eligible to self drive.\r\n                  <hr>\r\n                  <i class=\"fas fa-check-circle icon\"></i>The renter must be physically present at the car pick up and on return of the vehicle.\r\n              </div>\r\n                              </div>\r\n                          </div>\r\n                      </div>\r\n          \r\n                      <div style=\"margin-bottom: 20px;\">\r\n                          <a href=\"[[~30]]\" class=\"theme-btn btn-style-three btn-selection\" data-carcode=\"car_027\"  data-carname=\"Nissan Caravan\" data-carimage=\"assets/images/reg/car_027.png\">Select</a>\r\n</div>\r\n                      \r\n                  </div>\r\n              </div>\r\n          </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n          <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-6\">\r\n              <div cla